INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VXT_2022_consolidated', 'VXT', 2022, 'consolidated', 'Công ty có giao dịch với các bên liên quan là cổ đông bao gồm vay mượn, chi hộ, thu hộ với lãi suất thị trường (6%/năm cho vay cá nhân), không có bằng chứng giao dịch bất thường hoặc lãi suất ưu đãi đặc biệt.', 'Công ty có nợ vay ngắn hạn và dài hạn từ ngân hàng với lãi suất 9.5%/năm, được thế chấp bằng nhiều tài sản (ô tô, trái phiếu, bất động sản). Áp lực trả nợ ở mức trung bình do dòng tiền kinh doanh hoạt động dương mạnh (26.229.964.636 VND năm 2022), giúp bù đắp các khoản nợ đến hạn.', 'Hàng tồn kho chủ yếu là hàng hóa kinh doanh, đã trích lập dự phòng giảm giá 562.360.800 VND. Các dự án xây dựng dở dang có giá trị không lớn (tổng dưới 5 tỷ VND) và chưa ghi nhận dự phòng, không có dấu hiệu ứ đọng lớn.', 3, 'Công ty hoạt động kinh doanh có lãi tăng trưởng (lợi nhuận sau thuế tăng 20.6% so với năm trước), biên lợi nhuận gộp ở mức 23.35%. Cơ cấu tài sản chủ yếu là bất động sản đầu tư và hàng hóa. Nợ vay có tài sản đảm bảo đầy đủ. Dòng tiền kinh doanh mạnh cho thấy khả năng thanh toán tốt. Tuy nhiên, Công ty có giao dịch với bên liên quan là cổ đông và áp lực trả nợ ngắn hạn cần được theo dõi. Tổng thể, sức khỏe tài chính ổn định và triển vọng trung bình.'),
('VXT_2021_consolidated', 'VXT', 2021, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với cổ đông (Nguyễn Vạn Xuân, Trần Thị Vân Anh) dưới hình thức vay cá nhân lãi suất 6%/năm không có tài sản đảm bảo. Có các khoản chi hộ/thu hộ phát sinh với cổ đông Phan Ngọc Tân và Nguyễn Kim Cương (Tổng Giám đốc). Công ty con CNLube Việt Nam ký hợp đồng thuê kho với công ty mẹ. Cần đánh giá tính minh bạch và thị trường của các giao dịch này.', 'Tổng nợ vay đạt 41,46 tỷ VNĐ, trong đó nợ ngắn hạn chiếm 82% (34 tỷ VNĐ). Áp lực trả nợ ngắn hạn lớn. Nợ vay chủ yếu từ Agribank Hà Nội với lãi suất thả nổi và lãi suất nợ quá hạn rất cao (150% lãi suất trong hạn). Tài sản thế chấp bao gồm ô tô, bất động sản đầu tư và dự án xây dựng. Tỷ lệ nợ/vốn chủ sở hữu ~0.87.', 'Hàng tồn kho tăng mạnh 76% (từ 13,8 tỷ lên 24,9 tỷ VNĐ). Dự phòng giảm giá hàng tồn kho không thay đổi (562 triệu VNĐ) trong khi hàng hóa tăng mạnh cho thấy rủi ro dự phòng có thể chưa đầy đủ. Hàng tồn kho chủ yếu là hàng hóa kinh doanh (dầu, dung môi) chịu ảnh hưởng biến động giá nguyên liệu.', 6, 'Doanh nghiệp có doanh thu tăng nhẹ (8%) nhưng lợi nhuận giảm 43% do chi phí giá vốn tăng nhanh hơn. Dòng tiền hoạt động kinh doanh âm (-9,1 tỷ) trong khi đầu tư tài sản cố định mạnh (14,5 tỷ). Công ty tăng vốn từ 23,5 tỷ lên 36 tỷ VNĐ để trả nợ và bổ sung vốn lưu động. Có rủi ro về giao dịch với bên liên quan, áp lực nợ ngắn hạn, và dự phòng tồn kho. Công ty con CNLube Việt Nam (100%) hoạt động trong lĩnh vực liên quan.'),
('VXT_2022_parent', 'VXT', 2022, 'parent', 'Giao dịch với bên liên quan bao gồm bán hàng và mua hàng với công ty con, vay và trả nợ với cổ đông. Không có dấu hiệu bất thường như lãi suất không thị trường hoặc tài sản thế chấp không công bằng.', 'Áp lực nợ vay cao với nợ ngắn hạn chiếm phần lớn tổng nợ, nhưng tài sản thế chấp đầy đủ (xe ô tô, trái phiếu, bất động sản) và dòng tiền từ hoạt động kinh doanh mạnh.', 'Hàng tồn kho chủ yếu là hàng hóa thương mại, có dự phòng giảm giá nhưng không thay đổi so với năm trước, cho thấy rủi ro thấp. Dự án xây dựng dở dang có giá trị nhỏ.', 5, 'Công ty ghi nhận doanh thu và lợi nhuận tăng trưởng trong năm 2022, nhưng nợ vay tăng. Hoạt động kinh doanh chính là kinh doanh dầu mỡ và cho thuê kho bãi. Tuy nhiên, công ty có giao dịch với bên liên quan và nợ vay thế chấp, đòi hỏi quản trị thận trọng. Triển vọng phụ thuộc vào biến động giá dầu và hiệu quả quản lý tài sản.'),
('WCS_2022_consolidated', 'WCS', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại bình thường (cung cấp dịch vụ, mua hàng, chia cổ tức) với giá trị không đáng kể so với tổng doanh thu và tài sản. Không có dấu hiệu giao dịch bất thường hoặc có lợi cho bên liên quan.', 'Công ty có nợ ngắn hạn và dài hạn, nhưng mức độ tập trung rủi ro thấp và có khả năng tiếp cận vốn. Không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán và phải trả khác, không có lãi suất hoặc thế chấp cụ thể.', 'Hàng tồn kho chủ yếu là nguyên vật liệu nhỏ (giấy xác nhận, phiếu) với giá trị không đáng kể, không có rủi ro tồn kho lớn. Dự án xây dựng dở dang chủ yếu là nâng cấp và cải tạo, không có dấu hiệu ứ đọng.', 3, 'Công ty Cổ phần Bến Xe Miền Tây có sức khỏe tài chính tốt trong năm 2022 với sự phục hồi mạnh mẽ sau đại dịch COVID-19. Doanh thu và lợi nhuận tăng trưởng cao nhờ hoạt động kinh doanh chính (khai thác bến xe) phục hồi. Công ty có vị thế tài chính vững chắc, không có nợ vay ngân hàng, tài sản lưu động dồi dào. Rủi ro liên quan đến bên liên quan và nợ vay thấp. Triển vọng đầu tư tích cực trong ngắn hạn và trung hạn.'),
('VXT_2021_parent', 'VXT', 2021, 'parent', 'Công ty có giao dịch đáng kể với công ty con và cổ đông, bao gồm bán hàng, mua hàng, cho vay và vay vốn. Điều này có thể tạo ra xung đột lợi ích và rủi ro về giá chuyển nhượng không công bằng.', 'Công ty có nợ vay ngắn hạn và dài hạn với tổng số tiền lớn, được đảm bảo bằng tài sản cố định và bất động sản đầu tư. Áp lực trả nợ lãi cao, nhưng dòng tiền từ hoạt động kinh doanh có thể trang trải.', 'Hàng tồn kho tăng mạnh trong năm, nhưng đã trích lập dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình do hàng hóa là dầu nhớt và hóa chất có thị trường.', 6, 'Công ty hoạt động trong lĩnh vực kinh doanh dầu nhớt và cho thuê kho bãi. Doanh thu tăng nhưng lợi nhuận giảm do giá vốn tăng. Nợ vay cao và giao dịch với bên liên quan cần được giám sát chặt chẽ.'),
('VXT_2018_consolidated', 'VXT', 2018, 'consolidated', 'Công ty có giao dịch chi hộ cho cổ đông và thành viên HĐQT, cho vay cá nhân cổ đông với lãi suất 6%/năm (thấp hơn lãi suất ngân hàng). Đặc biệt, công ty đã bán 100% vốn công ty con (Miền Nam) với giá 0 đồng, ghi nhận lỗ 717.718.363 VND, đây là giao dịch có dấu hiệu bất thường, tiềm ẩn rủi ro về mặt quản trị và lợi ích của cổ đông thiểu số.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (35,6 tỷ VND), tập trung vào một ngân hàng chủ chốt, được thế chấp bằng xe ô tô. Áp lực trả nợ ngắn hạn cao, tuy nhiên dòng tiền từ hoạt động kinh doanh năm 2018 dương (9 tỷ VND) phần nào giảm bớt rủi ro thanh khoản. Nợ vay cá nhân có lãi suất ưu đãi nhưng không có tài sản đảm bảo.', 'Hàng tồn kho tăng nhẹ từ 22 tỷ lên 24,7 tỷ VND, chủ yếu là hàng hóa (dầu, hóa chất). Công ty đã trích lập dự phòng giảm giá 562 triệu VND. Rủi ro tồn kho ở mức trung bình, phụ thuộc vào biến động giá nguyên liệu thế giới.', 7, 'Công ty có doanh thu ổn định quanh mức 165-171 tỷ VND, lợi nhuận sau thuế tăng từ 4,26 tỷ lên 4,86 tỷ VND. Tuy nhiên, cơ cấu tài chính đòn bẩy cao với nợ vay ngắn hạn chiếm gần 50% tổng nguồn vốn. Các giao dịch với bên liên quan và việc bán công ty con với giá 0 đồng đặt ra câu hỏi về chất lượng quản trị. Công ty cần tăng cường quản lý dòng tiền và giảm phụ thuộc vào vay ngắn hạn để cải thiện sức khỏe tài chính.'),
('VXT_2020_consolidated', 'VXT', 2020, 'consolidated', 'Các giao dịch với bên liên quan (cổ đông, Tổng Giám đốc) có quy mô nhỏ và chủ yếu liên quan đến khoản vay cá nhân và chi hộ, không phát hiện giao dịch bất thường, mua bán chênh lệch lớn hay công ty sân sau đáng ngờ.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn trong cơ cấu vốn, chủ yếu là vay ngân hàng Nông nghiệp và vay cá nhân. Áp lực trả nợ ngắn hạn cao nhưng Công ty có dòng tiền kinh doanh và tài sản tài chính đáo hạn để thanh toán. Tài sản cố định hữu hình được dùng làm tài sản đảm bảo cho khoản vay.', 'Hàng tồn kho chủ yếu là hàng hóa đã thành phẩm, có trích lập dự phòng giảm giá. Tuy nhiên, giá trị hàng tồn kho giảm mạnh từ đầu năm, cho thấy luân chuyển hàng hóa tốt, không có dấu hiệu ứ đọng lớn.', 2, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng mạnh (lợi nhuận sau thuế tăng hơn 2.4 lần), biên lợi nhuận gộp ở mức tốt (~28%). Tuy nhiên, cơ cấu tài chính phụ thuộc nhiều vào nợ ngắn hạn, áp lực thanh toán nợ gốc lớn. Công ty đang trong giai đoạn đầu tư xây dựng trụ sở mới (chi phí xây dựng dở dang hơn 4.7 tỷ đồng) và tăng vốn điều lệ. Rủi ro quản trị ở mức thấp do không có giao dịch bên liên quan phức tạp hay bất thường.'),
('VXT_2018_parent', 'VXT', 2018, 'parent', 'Các giao dịch với bên liên quan bao gồm bán hàng, mua hàng, cho vay cổ đông và thanh toán hộ. Giá trị giao dịch không lớn so với quy mô doanh nghiệp, không có dấu hiệu bất thường明显. Tuy nhiên, cần theo dõi mối quan hệ cho vay với cổ đông.', 'Nợ vay chủ yếu là ngắn hạn, được đảm bảo bằng tài sản thế chấp. Công ty có khả năng thanh toán từ dòng tiền kinh doanh, nhưng áp lực nợ vay vẫn cao do tỷ lệ nợ trên vốn chủ sở hữu lớn.', 'Hàng tồn kho là hàng hóa, đã trích lập dự phòng giảm giá. Rủi ro tồn kho có thể do biến động thị trường hoặc hàng hóa chậm luân chuyển.', 3, 'Công ty có tình hình tài chính tương đối ổn định, lợi nhuận sau thuế tăng nhẹ so với năm trước. Nợ vay giảm, dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, hàng tồn kho tăng cần được theo dõi. Triển vọng đầu tư ở mức trung bình.'),
('VXT_2020_parent', 'VXT', 2020, 'parent', 'Công ty có giao dịch mua bán hàng hóa với công ty con (CNLube) với giá trị đáng kể. Có giao dịch chi hộ cho Chủ tịch Hội đồng quản trị. Tuy nhiên, không có bằng chứng về giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn bất hợp lý.', 'Nợ vay chủ yếu là ngắn hạn với tổng dư nợ lớn (27,5 tỷ VNĐ), áp lực trả nợ trong ngắn hạn cao. Các khoản vay được đảm bảo bằng tài sản thế chấp là ô tô và bất động sản. Công ty có dòng tiền từ hoạt động kinh doanh dương nhưng không đủ để bù đắp toàn bộ nhu cầu trả nợ, phụ thuộc vào việc đảo nợ và thu hồi công nợ.', 'Hàng tồn kho đã giảm so với năm trước và đã trích lập dự phòng giảm giá. Dự án xây dựng trụ sở văn phòng dở dang có thể bị ảnh hưởng bởi tiến độ thi công, thời gian dự kiến hoàn thành Quý II/2021.', 4, 'Công ty hoạt động trong lĩnh vực thương mại dầu mỡ, hóa chất và cho thuê kho bãi. Năm 2020, lợi nhuận sau thuế tăng mạnh (96,6 tỷ VNĐ so với 40,1 tỷ năm 2019) nhờ giảm giá vốn và chi phí. Tuy nhiên, cơ cấu tài chính phụ thuộc nhiều vào nợ ngắn hạn, tài sản cố định và bất động sản đầu tư chiếm tỷ trọng lớn và đã khấu hao nhiều. Dòng tiền từ hoạt động đầu tư âm do đầu tư vào công ty con và xây dựng trụ sở mới. Triển vọng phụ thuộc vào khả năng quản lý dòng tiền và hoàn thành dự án đầu tư.'),
('VXT_2016_consolidated', 'VXT', 2016, 'consolidated', 'Doanh nghiệp có giao dịch cho vay ngắn hạn với các thành viên ban lãnh đạo (Tổng Giám đốc, Phó Tổng Giám đốc, Thành viên HĐQT). Tổng số dư cuối kỳ là 1,350,000,000 VNĐ (Ông Nguyễn Văn Tỉnh: 1,000,000,000 VNĐ, Bà Trần Thị Thời: 350,000,000 VNĐ). Các khoản vay này không nêu rõ lãi suất và mục đích sử dụng, tiềm ẩn rủi ro về xung đột lợi ích và quản trị.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (37,077,923,757 VNĐ trên tổng tài sản ~102.8 tỷ). Nợ chủ yếu từ Agribank và vay cá nhân. Công ty có rủi ro thanh khoản ngắn hạn khi nợ phải trả tài chính đến hạn trong năm cao hơn đáng kể tài sản tài chính ngắn hạn.', 'Hàng tồn kho tăng từ 26.1 tỷ lên 28.2 tỷ. Dự phòng giảm giá giữ nguyên 551 triệu. Hàng tồn kho là hàng hóa (thành phẩm), rủi ro tồn kho không quá cao nhưng cần theo dõi khả năng tiêu thụ.', 6, 'Công ty đạt kết quả kinh doanh tốt với lợi nhuận sau thuế 51.9 tỷ (tăng mạnh so với năm trước 16.7 tỷ), chủ yếu nhờ lợi nhuận từ thanh lý, nhượng bán TSCĐ (61.6 tỷ). Tuy nhiên, lợi nhuận từ hoạt động kinh doanh chính giảm. Công ty có kiểm toán ngoại trừ do: (1) Chi phí lãi vay 842 triệu từ công ty con chưa được ghi nhận đúng kỳ; (2) Xóa sổ công nợ khó đòi 10.5 tỷ chưa có đủ hồ sơ; (3) Doanh thu/giá vốn nội bộ chưa loại trừ 7.3 tỷ. Cần lưu ý giao dịch cho vay với ban lãnh đạo và rủi ro thanh khoản ngắn hạn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VXT_2017_consolidated', 'VXT', 2017, 'consolidated', 'Công ty có giao dịch vay với các cổ đông, nhưng không có dấu hiệu bất thường. Các khoản vay có lãi suất và được hoàn trả đúng hạn.', 'Nợ vay chủ yếu là ngắn hạn từ ngân hàng và cá nhân, có tài sản thế chấp. Áp lực nợ vay cao do nợ ngắn hạn lớn, nhưng Công ty có khả năng thanh toán từ dòng tiền kinh doanh.', 'Hàng tồn kho là hàng hóa, có dự phòng giảm giá cho hàng chậm luân chuyển. Rủi ro tồn kho ở mức trung bình.', 5, 'Công ty có doanh thu ổn định, lợi nhuận giảm so với năm trước. Ý kiến kiểm toán ngoại trừ do phân loại tài sản và loại trừ giao dịch nội bộ. Nợ ngắn hạn cao, nhưng tài sản thế chấp đủ. Triển vọng trung bình.'),
('VXT_2017_parent', 'VXT', 2017, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt là cho vay không lãi suất hoặc lãi suất thấp cho cổ đông cá nhân, mua bán hàng hóa với công ty con. Điều này có thể tiềm ẩn rủi ro về giao dịch không công bằng và ảnh hưởng đến lợi ích của cổ đông thiểu số.', 'Áp lực nợ vay ngắn hạn cao với tổng nợ ngắn hạn 48.17 tỷ VNĐ, trong đó vay và nợ ngắn hạn 38.01 tỷ VNĐ. Công ty thế chấp tài sản cố định (xe ô tô) cho khoản vay ngân hàng. Khả năng thanh toán phụ thuộc vào dòng tiền hoạt động kinh doanh và thanh lý tài sản.', 'Hàng tồn kho giảm từ 27.14 tỷ VNĐ xuống 21.05 tỷ VNĐ, đã trích lập dự phòng 551 triệu VNĐ cho hàng hóa chậm luân chuyển. Rủi ro tồn kho ở mức có thể kiểm soát, nhưng vẫn tồn tại rủi ro giảm giá nếu thị trường dầu mỏ biến động.', 7, 'Tổng quan, doanh nghiệp hoạt động trong lĩnh vực kinh doanh dầu mỏ và dịch vụ kho vận. Sức khỏe tài chính trung bình: doanh thu giảm nhẹ, lợi nhuận sau thuế giảm mạnh từ 52.16 tỷ VNĐ (2016) xuống 4.27 tỷ VNĐ (2017) do giảm thu nhập từ thanh lý tài sản. Nợ ngắn hạn tăng, thanh khoản giảm. Tuy nhiên, vốn chủ sở hữu vẫn dương. Triển vọng đầu tư cần thận trọng do rủi ro liên quan đến giao dịch bên liên quan và áp lực nợ ngắn hạn.'),
('VXT_2016_parent', 'VXT', 2016, 'parent', 'Công ty có phát sinh nhiều giao dịch cho vay và nhận vay ngắn hạn không lãi suất với các thành viên Ban Tổng Giám đốc và thành viên Hội đồng quản trị (Ông Đỗ Ngọc Tiến, Ông Nguyễn Văn Tỉnh, Bà Trần Thị Thời, Ông Vũ Thanh Hà). Giá trị giao dịch cho vay trong năm tương đối lớn, với số dư cuối kỳ còn 1.350 triệu VND. Các giao dịch này cho thấy mối quan hệ tài chính phức tạp giữa công ty và ban lãnh đạo, có thể tiềm ẩn rủi ro về quản trị và xung đột lợi ích.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn trong tổng nợ phải trả (khoảng 50% nợ phải trả cuối kỳ), với tổng dư nợ cuối kỳ là 35.286 triệu VND. Các khoản vay chủ yếu từ Ngân hàng NN&PTNT Chi nhánh Hà Nội và từ cá nhân. Áp lực trả nợ ngắn hạn là đáng kể do toàn bộ nợ vay đều đến hạn dưới 1 năm. Công ty có tài sản ngắn hạn thanh khoản cao (tiền, đầu tư ngắn hạn) ở mức 47.663 triệu VND, đủ để bù đắp nợ vay ngắn hạn, song cơ cấu này cho thấy mức độ phụ thuộc vào việc duy trì dòng tiền hoạt động và khả năng đáo hạn, vay lại.', 'Hàng tồn kho cuối kỳ tăng nhẹ so với đầu kỳ, chủ yếu là hàng hóa. Công ty đã trích lập dự phòng giảm giá hàng tồn kho 551 triệu VND. Không có thông tin về dự án xây dựng dở dang. Rủi ro tồn kho ở mức thấp, tập trung vào rủi ro giảm giá thị trường đối với hàng hóa.', 6, 'Công ty có kết quả kinh doanh năm 2016 tăng đột biến so với năm trước (lợi nhuận sau thuế 52.157 triệu VND), tuy nhiên phần lớn đến từ thu nhập khác từ thanh lý, nhượng bán tài sản cố định (61.638 triệu VND), không phải từ hoạt động kinh doanh cốt lõi. Doanh thu thuần từ bán hàng và cung cấp dịch vụ thực tế giảm. Tình hình tài chính có một số điểm đáng lưu ý: (1) Kiểm toán viên đưa ra ý kiến ngoại trừ do chưa trích lập dự phòng đầu tư vào công ty con (334 triệu VND) và hồ sơ xóa sổ công nợ phải thu khó đòi (10.523 triệu VND) chưa đầy đủ; (2) Nợ vay ngắn hạn chiếm tỷ trọng cao; (3) Có nhiều giao dịch tài chính phức tạp với ban lãnh đạo. Công ty có lịch sử trả cổ tức tốt nhưng bền vững của lợi nhuận cao từ hoạt động phi thường cần được xem xét kỹ.'),
('VXP_2025_consolidated', 'VXP', 2025, 'consolidated', 'Không có giao dịch với các bên liên quan trong năm, rủi ro thấp.', 'Công ty có khoản vay ngắn hạn 200 triệu đồng nhưng chưa được đối chiếu xác nhận. Nợ phải trả khác lớn, áp lực thanh khoản cao và khả năng thu hồi một số khoản nợ chưa rõ ràng.', 'Tồn kho bao gồm nguyên liệu và sản phẩm dở dang chờ xuất trả kho dự trữ quốc gia, đã trích lập dự phòng giảm giá nhưng rủi ro ứ đọng vẫn tồn tại.', 6, 'Công ty đã cải thiện kết quả kinh doanh năm 2025 với lợi nhuận sau thuế dương, nhưng báo cáo kiểm toán có ý kiến ngoại trừ do nhiều khoản mục chưa được xác nhận. Tỷ suất lợi nhuận gộp tốt, nhưng rủi ro về nợ phải trả và tồn kho đáng lo ngại. Khả năng hoạt động liên tục được đảm bảo, nhưng điểm rủi ro quản trị ở mức trung bình.'),
('VXP_2024_consolidated', 'VXP', 2024, 'consolidated', 'Công ty có giao dịch tạm ứng cá nhân với Tổng Giám đốc Bùi Tuấn Anh (1.6 tỷ đồng trong năm), là giao dịch tiềm ẩn rủi ro xung đột lợi ích. Có khoản phải thu lớn với các bên liên quan là Navetco (2.18 tỷ), C.P. Việt Nam (2.28 tỷ). Công ty thuộc sở hữu chi phối của Bộ NN&PTNT (65%) và cổ đông chiến lược Nova Consumer (23.8%).', 'Rủi ro nợ vay CỰC KỲ CAO. Tỷ lệ nợ phải trả/tổng tài sản đạt 76.5%. Nợ phải trả toàn bộ là ngắn hạn (78.2 tỷ đồng). Boehringer Ingelheim - nhà cung cấp chính - nợ quá hạn 17.9 tỷ USD. Nợ hàng dự trữ quốc gia 36.1 tỷ đồng có tính chất đặc thù, khó thanh toán. Lãi vay NHPT 2.7 tỷ tồn đọng nhiều năm. Dòng tiền kinh doanh âm 6 tỷ, công ty không có khả năng trả nợ từ hoạt động sản xuất kinh doanh.', 'Tồn kho chiếm 50.4% tổng tài sản (51.5 tỷ đồng). Dự phòng giảm giá hàng tồn kho lên tới 16.1 tỷ đồng, tăng mạnh so với năm trước (11.9 tỷ). Thành phẩm có dự phòng 9 tỷ đồng cho thấy hàng hóa bị giảm giá trị đáng kể. Nguyên liệu dự phòng 7 tỷ đồng. Hàng hóa quốc gia 36.1 tỷ đồng có thể gặp khó khăn trong luân chuyển và xuất bán.', 9, 'VETVACO đang trong tình trạng tài chính NGUY HIỂM. Công ty lỗ nặng 2 năm liên tiếp (-20.1 tỷ 2023, -14.8 tỷ 2024), lỗ lũy kế -34.7 tỷ vượt vốn chủ sở hữu. Kiểm toán viên từ chối ý kiến do không thu thập đủ bằng chứng về khả năng thu hồi các khoản phải thu và phải trả. Hàng tồn kho chiếm tỷ trọng lớn với dự phòng giảm giá cao. Nợ phải trả toàn bộ ngắn hạn, trong đó nợ Boehringer Ingelheim quá hạn 17.9 tỷ. Công ty có nguy cơ mất khả năng thanh toán và hoạt động liên tục bị đe dọa nghiêm trọng.'),
('WSB_2020_parent', 'WSB', 2020, 'parent', 'Công ty có mức độ giao dịch với các bên liên quan rất lớn, đặc biệt với công ty mẹ Tổng Công ty CP Bia - Rượu - Nước Giải Khát Sài Gòn (doanh thu bán hàng 510 tỷ VND, mua nguyên vật liệu 99 tỷ VND). Khoản phải thu từ công ty mẹ 3,8 tỷ VND là không lãi suất và không có đảm bảo, cho thấy rủi ro tín dụng tiềm ẩn. Công ty cũng giao dịch mua bán với nhiều công ty liên quan khác trong hệ thống Sabeco (cơ khí Sa Be Co, thương mại Sông Hậu, Sông Tiền...). Doanh thu từ cổ tức chiếm tỷ trọng lớn trong doanh thu tài chính (71 tỷ VND/79,6 tỷ VND), chủ yếu từ công ty con và công ty liên kết.', 'Công ty không có khoản vay ngân hàng hay nợ vay dài hạn từ tổ chức tín dụng. Nợ phải trả chủ yếu là nợ ngắn hạn phát sinh từ hoạt động kinh doanh thông thường (phải trả người bán, thuế phải nộp). Tỷ lệ nợ phải trả trên tổng tài sản rất thấp chỉ khoảng 9,3%, cho thấy áp lực nợ vay gần như không tồn tại. Công ty có hệ số an toàn tài chính cao.', 'Hàng tồn kho ròng đạt 31,7 tỷ VND với dự phòng giảm giá 1,03 tỷ VND. Có 1.030 triệu VND phụ tùng thay thế chậm luân chuyển. Chi phí sản xuất dở dang 13,6 tỷ VND phản ánh quy trình sản xuất bia đang diễn ra bình thường. Xây dựng cơ bản dở dang giảm mạnh từ 7,9 tỷ xuống chỉ còn 2,7 triệu VND, cho thấy hầu hết dự án đã hoàn thành và chuyển sang tài sản cố định.', 5, 'Công ty CP Bia Sài Gòn - Miền Tây là công ty con thuộc hệ thống Sabeco với tình hình tài chính tương đối lành mạnh. Tổng tài sản 662,5 tỷ VND, vốn chủ sở hữu 600,6 tỷ VND. Lợi nhuận sau thuế 2020 giảm 29% so với 2019 do ảnh hưởng của Covid-19 và Nghị định 100/2019 về phòng chống tác hại rượu bia. Tuy nhiên, công ty vẫn duy trì tỷ suất lợi nhuận gộp 18,8% và dòng tiền từ hoạt động kinh doanh dương 56 tỷ VND. Công ty có khoản đầu tư lớn 200 tỷ VND vào công ty con (tăng 110 tỷ trong năm) và 110 tỷ VND tiền gửi có kỳ hạn. Rủi ro chính là phụ thuộc lớn vào công ty mẹ Sabeco về doanh thu và nguồn nguyên vật liệu, cũng như tác động tiêu cực từ đại dịch Covid-19 đến ngành đồ uống.'),
('VXP_2022_consolidated', 'VXP', 2022, 'consolidated', 'Không có giao dịch bất thường với các bên liên quan, các giao dịch chủ yếu là lương thưởng cho ban lãnh đạo.', 'Nợ vay thấp với khoản vay ngắn hạn 200 triệu VNĐ, lãi suất 0.63%/tháng, áp lực nợ vay không đáng kể.', 'Hàng tồn kho tăng từ 31 tỷ lên 42 tỷ VNĐ, có rủi ro ứ đọng do thiếu nguyên liệu từ nhà cung cấp chính Boehringer Ingelheim.', 3, 'Doanh thu giảm gần 30% so với năm trước, lợi nhuận sau thuế giảm mạnh từ 8 tỷ xuống 288 triệu VNĐ. Công ty gặp khó khăn do thiếu nguyên liệu từ nhà cung cấp, nhưng nợ vay thấp và tài sản cố định lớn. Triển vọng ngắn hạn không乐观, cần theo dõi vấn đề nhà cung cấp.'),
('VXP_2019_consolidated', 'VXP', 2019, 'consolidated', 'Không phát hiện giao dịch bất thường với bên liên quan. Các giao dịch chủ yếu là chi phí lương thưởng cho ban lãnh đạo, không có giao dịch mua bán, cho vay hay đầu tư phức tạp.', 'Áp lực nợ vay rất thấp với khoản vay ngắn hạn chỉ 302 triệu VNĐ (vay cán bộ công nhân viên) và không có nợ dài hạn. Công ty có đủ khả năng thanh toán từ dòng tiền kinh doanh.', 'Hàng tồn kho tăng mạnh từ 20,2 tỷ lên 35,4 tỷ VNĐ, chủ yếu do tăng nguyên liệu vật liệu. Dự phòng giảm giá hàng tồn kho chỉ 5,1 triệu VNĐ là không đáng kể. Rủi ro tồn kho ở mức trung bình do tăng mạnh hàng tồn kho.', 3, 'Công ty hoạt động sản xuất kinh doanh thuốc thú y có kết quả kinh doanh ổn định với lợi nhuận sau thuế đạt 6,57 tỷ VNĐ (giảm nhẹ so với năm trước). Nợ vay rất thấp, cơ cấu tài chính an toàn. Tồn kho tăng mạnh cần được theo dõi. Ban lãnh đạo có uy tín, không phát hiện giao dịch bất thường.'),
('VXP_2021_consolidated', 'VXP', 2021, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thu nhập của ban lãnh đạo, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Nợ vay thấp: nợ ngắn hạn 200 triệu VND, nợ dài hạn 1.187 tỷ VND. Công ty có khả năng thanh toán từ dòng tiền kinh doanh, rủi ro nợ vay không đáng kể.', 'Hàng tồn kho tăng mạnh từ 13.5 tỷ VND lên 31.1 tỷ VND, cần theo dõi khả năng tiêu thụ và nguy cơ ứ đọng, tuy nhiên dự phòng giảm giá cuối năm bằng 0.', 4, 'Tình hình tài chính ổn định, lợi nhuận sau thuế 8.056 tỷ VND, biên lợi nhuận gộp 30.53%. Nợ vay thấp, thanh khoản tốt. Tuy nhiên, tăng trưởng tồn kho nhanh cần được kiểm soát để tránh rủi ro.'),
('VXP_2018_consolidated', 'VXP', 2018, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là lương thưởng cho thành viên quản lý chủ chốt (2.1 tỷ VND) và khoản đầu tư vốn vào Công ty Cổ phần Anova (cổ đông 10%). Không phát hiện giao dịch bất thường hay giao dịch với công ty sân sau của ban lãnh đạo.', 'Nợ vay rất thấp, chỉ 302 triệu VND nợ ngắn hạn từ vay cán bộ nhân viên và 1.187 tỷ VND quỹ phát triển khoa học công nghệ (dài hạn). Tỷ lệ nợ vay/tổng tài sản cực thấp (~0.2%). Phải trả người bán tăng mạnh từ 35.7 tỷ lên 62.7 tỷ VND, trong đó có 16.6 tỷ VND liên quan đến hàng dự trữ quốc gia cho thấy mối quan hệ mật thiết với Nhà nước.', 'Hàng tồn kho tăng mạnh 49% từ 13.6 tỷ lên 20.2 tỷ VND, chủ yếu do thành phẩm tăng từ 7.1 tỷ lên 11.7 tỷ VND (tăng 64%). Hàng gửi bán giảm từ 2.3 tỷ xuống 1.9 tỷ VND. Dự phòng giảm giá hàng tồn kho giảm mạnh từ 493 triệu xuống chỉ còn 5 triệu VND. Tốc độ tăng tồn kho nhanh hơn tốc độ tăng doanh thu (24.7%) đặt ra câu hỏi về hiệu quả tiêu thụ.', 4, 'Công ty Cổ phần Thuốc Thú Y Trung ương Vet Va Co có kết quả kinh doanh tăng trưởng mạnh năm 2018: doanh thu thuần 227.6 tỷ VND (tăng 24.7%), lợi nhuận sau thuế 6.7 tỷ VND (tăng 42.4%). Biên lợi nhuận gộp ổn định ~32%. Vị thế tiền mặt tốt với 54.3 tỷ VND tiền và tương đương tiền. Nợ vay cực thấp, chủ yếu hoạt động bằng vốn chủ sở hữu. Tuy nhiên, hàng tồn kho và phải trả người bán tăng nhanh cần được giám sát. Công ty có 65% vốn Nhà nước, là đơn vị sản xuất thuốc thú y hàng đầu, hoạt động kinh doanh liên tục, không có rủi ro going concern.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VXP_2017_consolidated', 'VXP', 2017, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là lương cho ban lãnh đạo, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay thấp, chỉ có khoản vay ngắn hạn từ cán bộ công nhân viên với lãi suất 0.63%/tháng, áp lực nợ không đáng kể và không có tài sản thế chấp.', 'Hàng tồn kho giảm so với năm trước, có dự phòng cho thành phẩm, nhưng không có dấu hiệu ứ đọng lớn, rủi ro tồn kho ở mức trung bình.', 3, 'Công ty có kết quả kinh doanh tích cực với doanh thu và lợi nhuận tăng trưởng, dòng tiền hoạt động kinh doanh mạnh. Tuy nhiên, ý kiến kiểm toán ngoại trừ do vấn đề quyết toán cổ phần hóa chưa được giải quyết. Tình hình tài chính ổn định với nợ vay thấp và khả năng thanh toán tốt.'),
('VXP_2016_consolidated', 'VXP', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là lương cho ban lãnh đạo, không có giao dịch bất thường đáng kể.', 'Nợ vay ngắn hạn ở mức thấp, không có áp lực thanh toán lớn. Công ty quản lý thanh khoản thông qua tiền gửi ngân hàng.', 'Hàng tồn kho có dự phòng giảm giá, đặc biệt là thành phẩm. Cần theo dõi sát sao để tránh ứ đọng.', 6, 'Công ty có lợi nhuận sau thuế tăng trưởng, tài sản tăng mạnh do đầu tư tài sản cố định. Tuy nhiên, nợ phải trả tăng, hàng tồn kho giảm. Tình hình tài chính ổn định nhưng cần chú ý đến quản lý nợ và hàng tồn kho.'),
('VWS_2023_consolidated', 'VWS', 2023, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa, dịch vụ và thanh toán với các công ty liên kết. Giá trị giao dịch không lớn và được ghi nhận theo giá thị trường. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có các khoản vay ngân hàng. Nợ phải trả chủ yếu là nợ thương mại và khoản ký quỹ, ký cược. Áp lực trả nợ thấp, thanh khoản tốt với lượng tiền mặt và đầu tư ngắn hạn lớn.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang của các dự án tư vấn, xây dựng. Giá trị tăng nhẹ so với đầu năm. Rủi ro ứ đọng không cao do đây là chi phí cho các hợp đồng đang thực hiện.', 3, 'Doanh nghiệp có sức khỏe tài cơ bản ổn định, không có nợ vay, thanh khoản tốt. Tuy nhiên, doanh thu và lợi nhuận giảm so với năm trước. Cơ cấu cổ đông tập trung với cổ đông lớn là Tổng Công ty Tư vấn Xây dựng Việt Nam (35.35%).'),
('VWS_2025_consolidated', 'VWS', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu với các công ty liên kết, giá trị giao dịch không lớn so với quy mô doanh thu, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có các khoản vay ngân hàng, nợ phải trả chủ yếu là nợ phải trả người bán và người mua trả trước, áp lực trả nợ thấp. Công ty có đủ tiền và tương đương tiền để thanh toán các nghĩa vụ nợ.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang và các dự án xây dựng dở dang, không có dự phòng giảm giá. Rủi ro liên quan đến tiến độ và khả năng thu hồi từ các dự án, nhưng hiện tại chưa có dấu hiệu ứ đọng nghiêm trọng.', 3, 'Công ty hoạt động trong lĩnh vực tư vấn và xây dựng hạ tầng. Doanh thu tăng nhưng lợi nhuận giảm so với năm trước do chi phí tăng. Tình hình tài chính ổn định với tỷ lệ nợ thấp, thanh khoản tốt. Công ty có mối quan hệ với các công ty liên kết nhưng giao dịch minh bạch. Điểm rủi ro quản trị thấp, triển vọng kinh doanh phụ thuộc vào tình hình đầu tư hạ tầng.'),
('VWS_2024_consolidated', 'VWS', 2024, 'consolidated', 'Công ty có giao dịch với các công ty liên kết và cổ đông lớn. Các giao dịch chủ yếu là mua bán dịch vụ, nhận thanh toán và chia cổ tức, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng. Nợ phải trả chủ yếu là nợ thương mại (phải trả người bán, người mua trả trước, thuế, phải trả người lao động). Áp lực nợ thấp, khả năng thanh toán tốt.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, không trích lập dự phòng. Rủi ro là các dự án có thể kéo dài, chậm tiến độ hoặc phát sinh chi phí vượt dự toán.', 4, 'Công ty có sức khỏe tài chính ổn định với tỷ suất lợi nhuận gộp khoảng 11.89%. Doanh thu giảm so với năm trước nhưng lợi nhuận tăng mạnh nhờ thu nhập lớn từ chuyển nhượng dự án. Dòng tiền hoạt động kinh doanh dương, thanh khoản tốt. Công ty không có nợ vay ngân hàng, giảm áp lực tài chính. Tuy nhiên, doanh thu cốt lõi (tư vấn, thiết kế) giảm, phụ thuộc vào các dự án lớn. Triển vọng phụ thuộc vào khả năng hoàn thành các dự án dở dang và duy trì mối quan hệ với khách hàng, đối tác.'),
('VWS_2021_consolidated', 'VWS', 2021, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa và dịch vụ với các công ty liên kết với giá trị lớn (mua hàng khoảng 3,8 tỷ đồng, bán hàng khoảng 160 triệu đồng). Ngoài ra, Công ty nhận cổ tức từ các công ty liên kết. Các giao dịch này có thể không hoàn toàn độc lập, nhưng chưa có dấu hiệu bất thường nghiêm trọng.', 'Công ty không có vay nợ ngân hàng, nợ phải trả chủ yếu là người mua trả trước và phải trả người bán. Rủi ro nợ thấp, thanh khoản tốt.', 'Hàng tồn kho là chi phí sản xuất kinh doanh dở dang, tăng so với năm trước. Các dự án dở dang có thể chậm tiến độ, nhưng chưa trích lập dự phòng giảm giá. Cần theo dõi tiến độ thực hiện.', 4, 'Công ty có tình hình tài chính lành mạnh, không có nợ vay, lợi nhuận giảm so với năm trước nhưng vẫn dương. Dòng tiền kinh doanh dương. Rủi ro quản trị ở mức chấp nhận được.'),
('VWS_2020_consolidated', 'VWS', 2020, 'consolidated', 'Giao dịch với bên liên quan bao gồm mua bán hàng hóa và nhận cổ tức từ các công ty liên kết, tỷ lệ nhỏ so với doanh thu, không có dấu hiệu bất thường.', 'Công ty không có nợ vay ngân hàng, tỷ lệ nợ thuần trên vốn chủ sở hữu 0%, rủi ro nợ thấp.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, đã giảm so với đầu năm, không có dự phòng giảm giá, rủi ro tồn kho thấp.', 3, 'Công ty có tình hình tài chính ổn định, không nợ vay, lợi nhuận tăng trưởng nhẹ, dòng tiền hoạt động kinh doanh dương, triển vọng đầu tư trung bình.'),
('VWS_2018_consolidated', 'VWS', 2018, 'consolidated', 'Công ty có giao dịch mua bán qua lại với các công ty liên doanh, liên kết (Sài Gòn, Phương Đông, Lạc Việt). Các giao dịch chủ yếu là thầu phụ và cho thuê văn phòng với giá trị không quá lớn so với tổng tài sản. Tuy nhiên, cần lưu ý tỷ lệ sở hữu lớn (trên 44%) tại các công ty này có thể dẫn đến xung đột lợi ích trong các giao dịch giá chuyển nhượng.', 'Công ty không có nợ vay ngân hàng dài hạn hay ngắn hạn. Các khoản nợ ngắn hạn chủ yếu là phải trả người bán (3.935 tỷ), người mua trả trước (15.705 tỷ) và phải trả ngắn hạn khác (22.741 tỷ). Áp lực nợ thấp do không phải chịu chi phí lãi vay, tuy nhiên lượng tiền mặt giảm mạnh từ 24.889 tỷ xuống 11.862 tỷ.', 'Hàng tồn kho chủ yếu là chi phí SXKD dở dang (9.551 tỷ), đã giảm so với đầu năm (12.681 tỷ). Dự án xây dựng cơ bản dở dang (12.264 tỷ) tăng mạnh, tập trung vào bất động sản văn phòng. Rủi ro tồn kho ở mức trung bình do dự án có giá trị thu hồi đảm bảo.', 5, 'Doanh thu giảm 9.6% từ 143.959 tỷ xuống 130.204 tỷ, lợi nhuận sau thuế giảm mạnh 69.7% từ 18.991 tỷ xuống 5.744 tỷ. Dòng tiền từ hoạt động kinh doanh âm 2.145 tỷ. Công ty không có nợ vay, tài sản chủ yếu là đầu tư dài hạn và xây dựng dở dang. Cổ tức chi trả cao (10.800 tỷ) so với lợi nhuận, làm giảm vốn chủ sở hữu. Triển vọng trung bình, cần cải thiện hiệu quả kinh doanh và quản lý dòng tiền.'),
('VWS_2019_consolidated', 'VWS', 2019, 'consolidated', 'Giao dịch với các bên liên quan bao gồm mua bán hàng và nhận cổ tức từ công ty liên kết. Giá trị giao dịch không quá lớn so với tổng doanh thu, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá bất thường.', 'Công ty không có nợ vay tài chính, chỉ có các khoản phải trả ngắn hạn từ hoạt động kinh doanh. Rủi ro nợ thấp do không có áp lực trả nợ gốc và lãi, thanh khoản tốt.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang và dự án xây dựng dở dang. Giá trị tồn kho giảm so với năm trước, cho thấy công ty đã hoàn thành một phần công việc, nhưng cần theo dõi tiến độ dự án để tránh ứ đọng.', 4, 'Công ty có tình hình tài chính ổn định với tỷ lệ nợ thấp, lợi nhuận dương nhưng giảm so với năm trước. Doanh thu từ dịch vụ tư vấn chiếm tỷ trọng cao, áp lực cạnh tranh. Công ty có dòng tiền hoạt động kinh doanh dương, thanh khoản đảm bảo. Tuy nhiên, cần quản lý chi phí và theo dõi tiến độ dự án để duy trì hiệu quả.'),
('VWS_2017_consolidated', 'VWS', 2017, 'consolidated', 'Rủi ro thấp, các giao dịch với bên liên quan nằm trong phạm vi hoạt động kinh doanh bình thường và không có dấu hiệu bất thường.', 'Không có nợ vay ngân hàng, rủi ro nợ thấp, công ty có khả năng thanh toán tốt.', 'Hàng tồn kho chủ yếu là chi phí sản xuất, kinh doanh dở dang và xây dựng cơ bản dở dang, không có dự phòng giảm giá, rủi ro tồn kho không đáng kể.', 5, 'Tình hình tài chính của công ty tốt, lợi nhuận tăng trưởng, tiền mặt dồi dào, không có gánh nặng nợ vay. Tuy nhiên, doanh thu phụ thuộc vào các dự án tư vấn và xây dựng, cần theo dõi biến động thị trường.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VWS_2016_consolidated', 'VWS', 2016, 'consolidated', 'Công ty có giao dịch với các bên liên quan như công ty liên kết và nhân sự chủ chốt, chủ yếu là thầu phụ và thiết kế với giá trị không quá lớn, không có dấu hiệu bất thường rõ ràng.', 'Công ty không có nợ vay dài hạn, chỉ có các khoản phải trả ngắn hạn từ hoạt động kinh doanh thông thường, áp lực nợ thấp.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang và chi phí xây dựng cơ bản dở dang, giá trị đáng kể nhưng không có dự phòng, rủi ro tồn kho ở mức trung bình.', 4, 'Công ty có kết quả kinh doanh tăng trưởng tốt, biên lợi nhuận gộp khoảng 13%, thanh toán hiện hành đảm bảo, cơ cấu tài sản và vốn hợp lý. Tuy nhiên, doanh thu phụ thuộc vào các dự án tư vấn và xây dựng, cần theo dõi tiến độ các dự án và quản lý vốn lưu động.'),
('VWS_2015_consolidated', 'VWS', 2015, 'consolidated', 'Công ty có giao dịch với các công ty liên kết với giá trị không lớn, nhưng cần theo dõi tính minh bạch và công bằng trong các giao dịch này.', 'Công ty không có nợ vay, chủ yếu là nợ phải trả ngắn hạn. Tỷ số thanh toán hiện hành là 1.29, thanh khoản ở mức trung bình.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang với giá trị lớn, có thể rủi ro nếu dự án bị chậm trễ hoặc không hiệu quả.', 3, 'Công ty có lợi nhuận tăng trưởng, nhưng thanh khoản trung bình và tồn kho dở dang cao. Cơ cấu vốn ổn định với tỷ lệ nợ/vốn thấp.'),
('VW3_2024_consolidated', 'VW3', 2024, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan thuộc hệ sinh thái Tổng Công ty Đầu tư Nước và Môi trường Việt Nam - CTCP (công ty mẹ). Đáng chú ý, Công ty cho vay ngắn hạn 600 triệu VND không lãi suất đối với công ty mẹ và có khoản phải thu thương mại 4,87 tỷ VND từ công ty mẹ. Các giao dịch này có mức độ rủi ro trung bình do tính chất liên kết nội bộ, tuy nhiên chưa phát hiện dấu hiệu bất thường nghiêm trọng về giá chuyển nhượng hay điều kiện giao dịch.', 'Áp lực nợ vay thấp. Tại ngày 31/12/2024, Công ty chỉ còn nợ vay ngắn hạn 3.66 tỷ VND từ Ngân hàng TMCP Tiên Phong (giảm mạnh từ 13.63 tỷ VND đầu năm), tỷ lệ nợ/vốn chủ sở hữu chỉ 0.08 lần. Tài sản đảm bảo là quyền đòi nợ từ các chủ đầu tư. Chi phí lãi vay năm 2024 là 504 triệu VND (giảm 52% so với năm trước). Tuy nhiên, Công ty có khoản phải thu quá hạn 25.11 tỷ VND từ các dự án ngân sách nhà nước chờ quyết toán, tiềm ẩn rủi ro thanh khoản nếu thu hồi chậm.', 'Hàng tồn kho giảm từ 32.5 tỷ xuống 24.4 tỷ VND. Phần lớn là chi phí sản xuất kinh doanh dở dang (17.8 tỷ VND) bao gồm nhiều gói thầu xây lắp, trong đó gói thầu 19 Vành đai 3,5 chiếm 13.5 tỷ VND. Nguyên liệu vật liệu 6.56 tỷ VND chủ yếu là ống gang, ống thép thừa do thay đổi thiết kế chủ đầu tư. Công ty đánh giá không cần trích lập dự phòng nhưng rủi ro ứ đọng vật tư vẫn tồn tại.', 5, 'Công ty VIWASEEN3 hoạt động trong lĩnh vực xây lắp cấp thoát nước, là công ty con của Tổng Công ty Đầu tư Nước và Môi trường Việt Nam - CTCP (sở hữu 54.5%). Năm 2024, doanh thu giảm 26% từ 360.5 tỷ xuống 265.2 tỷ VND, lợi nhuận sau thuế giảm 38% từ 2.9 tỷ xuống 1.8 tỷ VND. Biên lợi nhuận gộp ổn định khoảng 5.2%. Dòng tiền hoạt động kinh doanh âm 7.06 tỷ VND do giảm mạnh các khoản phải trả. Công ty có hệ số thanh toán tốt, nợ vay thấp, nhưng phụ thuộc lớn vào công ty mẹ và các dự án ngân sách nhà nước. Đội ngũ nhân sự thu hẹp từ 76 xuống 42 người. Lợi nhuận cơ bản trên cổ phiếu đạt 899 VND/cổ phần. Công ty tiếp tục chia cổ tức 8% vốn điều lệ. Triển vọng trung lập, phụ thuộc vào tiến độ quyết toán các dự án và khả năng thu hồi công nợ quá hạn.'),
('VW3_2025_consolidated', 'VW3', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thanh toán cổ tức cho cổ đông lớn là công ty mẹ và các công ty cùng mẹ, không có giao dịch bất thường hay cho vay không lãi suất.', 'Công ty có khoản vay ngắn hạn 1,48 tỷ VNĐ từ ngân hàng, được đảm bảo bằng quyền đòi nợ từ hợp đồng thi công. Áp lực nợ vay không cao nhưng thanh khoản phụ thuộc vào thu hồi công nợ.', 'Hàng tồn kho lớn (28,07 tỷ VNĐ) trong đó nguyên vật liệu tồn kho 6,56 tỷ VNĐ đã lâu không biến động và chưa được đánh giá giảm giá, có nguy cơ phải trích lập dự phòng. Chi phí sản xuất dở dang cao cho thấy dự án thi công có thể bị ứ đọng.', 6, 'Công ty kinh doanh trong lĩnh vực xây dựng cấp thoát nước, năm 2025 ghi nhận doanh thu giảm mạnh so với 2024, lợi nhuận gộp âm, lỗ sau thuế 5,84 tỷ VNĐ. Vốn điều lệ chỉ 20 tỷ VNĐ, không đủ điều kiện là công ty đại chúng theo Luật Chứng khoán. Kiểm toán viên đưa ra ý kiến ngoại trừ do chưa trích lập đủ dự phòng cho hàng tồn kho và công nợ phải thu quá hạn. Tình hình tài chính tiềm ẩn rủi ro, triển vọng đầu tư không tích cực.'),
('VW3_2022_consolidated', 'VW3', 2022, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cổ tức và tiền thuê đất, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay toàn bộ ngắn hạn, được đảm bảo bằng tài sản, nhưng lưu chuyển tiền từ hoạt động kinh doanh âm trong năm 2022 (-4,67 tỷ VNĐ), cho thấy áp lực thanh khoản. Cần theo dõi khả năng trả nợ.', 'Hàng tồn kho chủ yếu là vật liệu và chi phí sản xuất dở dang, không trích lập dự phòng giảm giá. Tuy nhiên, vật liệu tồn kho do thay đổi thiết kế có thể ảnh hưởng đến tiến độ dự án.', 3, 'Công ty có doanh thu ổn định khoảng 254 tỷ VNĐ nhưng lợi nhuận gộp giảm. Lưu chuyển tiền từ hoạt động kinh doanh âm, cần tăng cường quản lý dòng tiền. Nợ vay ngắn hạn được kiểm soát tốt với tài sản thế chấp. Triển vọng ở mức trung bình.'),
('VW3_2021_consolidated', 'VW3', 2021, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan thuộc hệ thống Tổng Công ty Đầu tư Nước và Môi trường Việt Nam - CTCP, bao gồm: phải thu khách hàng 4,87 tỷ từ công ty mẹ (quá hạn trên 3 năm), thanh toán cổ tức 1,74 tỷ cho công ty mẹ, và tiền thuê đất 49,9 triệu. Nhiều công ty con cùng hệ thống (Viwaseen 1, 2, 4) cũng nhận cổ tức. Số dư phải thu từ công ty mẹ 4,87 tỷ đã quá hạn 3 năm nhưng chưa trích lập dự phòng bổ sung, cho thấy mức độ tin tưởng vào khả năng thu hồi từ bên liên quan. Tổng thể giao dịch với bên liên quan không bất thường nhưng mức độ liên kết cao.', 'Nợ vay ngắn hạn giảm từ 31,6 tỷ xuống 24,5 tỷ, cho thấy công ty đã tích cực trả nợ. Tuy nhiên, toàn bộ nợ là ngắn hạn (không có nợ dài hạn), tạo áp lực tái tục thường xuyên. Tài sản thế chấp bao gồm bất động sản tại Cầu Giấy và ô tô. Công ty có lượng tiền mặt tốt (16,6 tỷ) và dòng tiền hoạt động kinh doanh dương mạnh (20,4 tỷ), khả năng thanh toán nợ vay được đảm bảo.', 'Hàng tồn kho tăng mạnh từ 25,2 tỷ lên 63,1 tỷ (tăng 150%), trong đó chi phí sản xuất dở dang chiếm 55,8 tỷ (88% tổng tồn kho). Các công trình lớn như CW2 Vĩnh Phúc, Ô19B Hoàng Mai, nhà máy nước Hoà Liên đang trong quá trình thi công. Nguyên vật liệu tồn kho 7,25 tỷ do thay đổi thiết kế của chủ đầu tư dẫn đến thừa, tuy Công ty đánh giá vẫn đảm bảo chất lượng nhưng chưa trích lập dự phòng. Rủi ro tồn kho ở mức trung bình cao do phụ thuộc vào tiến độ thanh toán của chủ đầu tư và quyết toán dự án Ngân sách.', 6, 'Viwaseen 3 có sức khỏe tài chính cải thiện đáng kể: doanh thu tăng 88% (252,9 tỷ), lợi nhuận sau thuế tăng 72% (2,35 tỷ), dòng tiền kinh doanh dương mạnh 20,4 tỷ. Công ty giảm được nợ vay và tăng tiền mặt. Tuy nhiên, các rủi ro bao gồm: (1) khoản phải thu quá hạn 17,7 tỷ từ các dự án Ngân sách chưa quyết toán, (2) hàng tồn kho tăng vọt do dở dang thi công, (3) tỷ lệ nợ ngắn hạn cao (24,5 tỷ), (4) chi phí khác tăng đột biến 1,26 tỷ (tiền phạt). Công ty có nền tảng kinh doanh xây lắp cấp thoát nước ổn định với doanh thu xây lắp 228 tỷ và mới mở rộng sang bất động sản (24,6 tỷ). Triển vọng phụ thuộc vào khả năng thu hồi nợ từ dự án Ngân sách và tiến độ thi công các công trình dở dang.'),
('VW3_2023_consolidated', 'VW3', 2023, 'consolidated', 'Công ty có giao dịch với các bên liên quan chủ yếu là công ty mẹ và các công ty cùng công ty mẹ, bao gồm chi trả cổ tức và thuê đất. Các giao dịch này có vẻ bình thường và không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn từ các ngân hàng với tổng số dư khoảng 13.6 tỷ VND tại ngày 31/12/2023, được đảm bảo bằng tài sản như quyền đòi nợ và hàng hóa. Áp lực nợ vay ở mức vừa phải do tỷ lệ nợ trên tài sản thấp và dòng tiền kinh doanh dương.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất dở dang. Nguyên vật liệu có thể bị tồn đọng do thay đổi thiết kế, nhưng công ty đánh giá vẫn đảm bảo chất lượng và không cần trích lập dự phòng. Các dự án dở dang có thể có rủi ro chậm tiến độ hoặc thay đổi thiết kế từ chủ đầu tư.', 3, 'Tình hình tài chính của Công ty ổn định với doanh thu tăng trưởng 42% và lợi nhuận tăng 2.6% so với năm trước. Công ty có tỷ suất lợi nhuận gộp khoảng 5.2%, nhưng chi phí quản lý và thuế cao. Các khoản phải thu quá hạn lớn nhưng được đánh giá có khả năng thu hồi. Triển vọng đầu tư trung bình, cần theo dõi tiến độ các dự án và quản lý dòng tiền.'),
('VW3_2020_consolidated', 'VW3', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi trả cổ tức và thu nhập cho ban lãnh đạo, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Công ty có nợ vay ngắn hạn với tổng dư nợ 31,6 tỷ VNĐ, được đảm bảo bằng tài sản như bất động sản, xe cộ và quyền đổi nợ từ hợp đồng thi công. Nợ quá hạn thanh toán là 29,4 tỷ VNĐ, chủ yếu từ các dự án vốn ngân sách nhà nước, nhưng Ban Giám đốc đánh giá có khả năng thu hồi. Áp lực nợ vay trung bình, khả năng thanh toán ổn định.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, không trích lập dự phòng. Vật tư thừa do thay đổi thiết kế nhưng vẫn đảm bảo chất lượng. Dự án bất động sản đã hoàn thành và chuyển nhượng, không có ứ đọng.', 3, 'Công ty hoạt động trong ngành cấp thoát nước và xây dựng, doanh thu giảm mạnh từ 281 tỷ xuống 134 tỷ VNĐ do ảnh hưởng của Covid-19. Lợi nhuận sau thuế giảm từ 3,5 tỷ xuống 1,4 tỷ VNĐ. Công ty có nợ vay ngắn hạn nhưng được đảm bảo tài sản, nợ quá hạn lớn nhưng dự kiến thu hồi. Tình hình tài chính ổn định, nhưng triển vọng phụ thuộc vào thanh toán công nợ từ dự án ngân sách.'),
('VVS_2025_consolidated', 'VVS', 2025, 'consolidated', 'Giao dịch vay mượn với thành viên Hội đồng quản trị với lãi suất 6.5%/năm, không có tài sản đảm bảo, nhưng tỷ trọng nợ vay bên liên quan trên tổng nợ vay thấp (khoảng 7%), rủi ro không đáng kể.', 'Nợ vay ngắn hạn tăng mạnh, nhưng Công ty có dòng tiền kinh doanh dương mạnh và các khoản phải thu ngắn hạn lớn, đảm bảo khả năng thanh toán. Tài sản thế chấp chủ yếu là hàng hóa và tiền gửi.', 'Hàng tồn kho chủ yếu là ô tô thành phẩm, không có dự phòng giảm giá, tồn kho tương đối ổn định so với doanh thu.', 4, 'Công ty tăng trưởng mạnh trong năm 2025, lợi nhuận sau thuế tăng 369% nhờ doanh thu tăng đột biến và quản lý tài chính hiệu quả. Tuy nhiên, nợ vay ngắn hạn tăng cao đòi hỏi quản lý dòng tiền chặt chẽ. Triển vọng tích cực với dự án nhà máy mới.'),
('VW3_2019_consolidated', 'VW3', 2019, 'consolidated', 'Công ty có các giao dịch với bên liên quan chủ yếu là trả cổ tức cho công ty mẹ và các công ty con, đồng thời có khoản phải thu khách hàng lớn (8,5 tỷ VND) từ công ty mẹ. Khoản phải thu này chiếm tỷ trọng đáng kể trong tổng tài sản ngắn hạn, tạo rủi ro về khả năng thu hồi nếu công ty mẹ gặp khó khăn tài chính. Không phát hiện giao dịch bất thường về giá hay điều kiện ưu đãi quá mức.', 'Công ty có nợ vay ngắn hạn với tổng giá trị khoảng 50,4 tỷ VND, chủ yếu từ hai ngân hàng thương mại và một khoản vay cá nhân. Tài sản đảm bảo bao gồm tài sản cá nhân của ban giám đốc/hội đồng quản trị, xe ô tô và toàn bộ các khoản phải thu từ hợp đồng thi công, cho thấy mức độ rủi ro cao nếu doanh nghiệp không duy trì được dòng tiền hoạt động ổn định để trả nợ đúng hạn. Áp lực trả nợ ngắn hạn là đáng kể.', 'Hàng tồn kho giảm mạnh từ 153 tỷ xuống 58 tỷ VND, chủ yếu do chi phí sản xuất kinh doanh dở dang giảm. Tuy nhiên, vẫn còn nhiều gói thầu xây dựng dở dang với giá trị lớn. Rủi ro tồn kho dở dang có thể phát sinh nếu các công trình không được nghiệm thu thanh toán đúng tiến độ, dẫn đến khả năng ứ đọng vốn và ảnh hưởng đến dòng tiền.', 5, 'Công ty hoạt động trong lĩnh vực xây lắp cấp thoát nước, doanh thu ổn định quanh mức 280 tỷ VND nhưng lợi nhuận sau thuế giảm từ 7,27 tỷ xuống 3,47 tỷ VND. Điểm đáng chú ý là áp lực nợ vay ngắn hạn lớn (50,4 tỷ VND) với tài sản đảm bảo chủ yếu từ tài sản cá nhân ban lãnh đạo, kết hợp với khoản phải thu lớn từ công ty mẹ. Hàng tồn kho (chủ yếu là chi phí dở dang) giảm mạnh nhưng vẫn ở mức cao. Công ty đang triển khai dự án xây dựng trụ sở mới. Triển vọng phụ thuộc vào khả năng thu hồi công nợ, quản lý dòng tiền trả nợ và tiến độ thi công các gói thầu. Điểm rủi ro quản trị ở mức trung bình.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VVS_2025_parent', 'VVS', 2025, 'parent', 'Công ty có các giao dịch với bên liên quan chủ yếu là vay vốn từ thành viên Hội đồng Quản trị với lãi suất 6.5%/năm, không có tài sản đảm bảo. Các giao dịch này được công khai và lãi suất phù hợp với thị trường, không phát hiện dấu hiệu bất thường.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn, với tổng số dư 557.846.792.599 VND, được đảm bảo bằng tài sản hình thành từ vốn vay, tiền gửi và bất động sản. Áp lực nợ vay cao do nợ đến hạn trong ngắn hạn, nhưng công ty có dòng tiền hoạt động mạnh và tiền gửi lớn tại các ngân hàng.', 'Hàng tồn kho chủ yếu là hàng hóa (xe ô tô) với giá trị cao, không trích lập dự phòng giảm giá. Rủi ro tồn kho thấp do không có dự án dở dang, nhưng cần theo dõi biến động thị trường xe.', 3, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận năm 2025, nhờ vào sự phục hồi của thị trường xe tải và chiến lược đa dạng hóa sản phẩm. Tuy nhiên, nợ vay ngắn hạn cao và tập trung vào nhà cung cấp chính là Sinotruk International. Quản trị tài chính hiệu quả với chi phí tài chính giảm, nhưng cần lưu ý rủi ro tỷ giá và thanh khoản ngắn hạn.'),
('VVN_2025_consolidated', 'VVN', 2025, 'consolidated', 'Doanh nghiệp có số lượng lớn giao dịch với các bên liên quan, đặc biệt là mua bán hàng hóa với Công ty CP Cơ khí Thương mại Xây lắp Điện 4 (liên kết) lên tới 226,4 tỷ VND trong năm 2025. Tổng mua hàng với bên liên quan là 286,6 tỷ VND. Các khoản phải trả người bán cho bên liên quan là 104,1 tỷ VND. Công ty TNHH MTV Xi măng Quang Sơn (công ty con) ghi nhận khoản lỗ lũy kế nghiêm trọng (lỗ 650,8 tỷ VND trong năm 2025). Cần lưu ý mối quan hệ kinh doanh chặt chẽ giữa Tổng Công ty và các công ty liên kết, có thể tạo ra xung đột lợi ích hoặc giao dịch không theo giá thị trường.', 'Tổng nợ vay và nợ thuê tài chính lên tới 4.752 tỷ VND (ngắn hạn 835 tỷ, dài hạn 3.917 tỷ), trong đó nợ quá hạn chưa thanh toán là 2.186 tỷ VND (chiếm 46% tổng nợ). Nợ vay vượt xa tổng tài sản (4.505 tỷ VND), cho thấy doanh nghiệp hoạt động hoàn toàn bằng vốn vay. Chi phí lãi vay trong năm 2025 là 224,5 tỷ VND, tăng so với năm 2024 (206,3 tỷ VND). Nợ dài hạn chủ yếu từ Bộ Tài chính (2.566 tỷ VND) và Ngân hàng Phát triển khu vực Bắc Kạn Thái Nguyên (1.342 tỷ VND). Tài sản cố định có giá trị còn lại dùng để thế chấp cầm cố khoản vay là 1.274 tỷ VND.', 'Chi phí sản xuất kinh doanh dở dang chiếm tỷ trọng lớn (654 tỷ VND), tăng so với năm trước. Kiểm toán viên đánh giá là chưa đủ cơ sở để xác định giá trị các công trình dở dang do chưa thanh quyết toán với chủ đầu tư. Dự phòng giảm giá hàng tồn kho là 12,9 tỷ VND, tập trung chủ yếu vào Công trình Gang thép Thái Nguyên giai đoạn 2. Nhiều công trình dở dang có giá trị lớn như TBA 220kV Hải Hậu, ĐZ 500kV Monsoon - Thạch Mỹ, Nhà máy điện khí LNG Hiệp Phước cần được theo dõi sát tiến độ thanh quyết toán.', 8, 'Doanh nghiệp đang trong tình trạng tài chính rất khó khăn. Vốn chủ sở hữu âm 2.751 tỷ VND do lỗ lũy kế tích lũy 3.598 tỷ VND. Nợ phải trả (7.257 tỷ VND) vượt tổng tài sản (4.505 tỷ VND), cho thấy nguy cơ mất khả năng thanh toán. Doanh thu giảm 9% (từ 4.400 tỷ xuống 4.005 tỷ VND). Lĩnh vực xi măng lỗ nặng (Công ty TNHH MTV Xi măng Quang Sơn lỗ 650 tỷ VND). Biên lợi nhuận gộp rất thấp (1,82%). Kiểm toán viên đưa ra ý kiến ngoại trừ về các khoản công trình dở dang và công nợ tồn đọng. Điểm rủi ro quản trị cao (8/10) do cấu trúc phức tạp với 13 công ty con và 12 công ty liên kết, nhiều giao dịch nội bộ, và năng lực quản trị tài chính yếu.'),
('VVN_2024_consolidated', 'VVN', 2024, 'consolidated', 'Công ty có giao dịch mua hàng hóa đáng kể với các công ty liên kết, nổi bật là Công ty CP Cơ khí Thương mại Xây lắp Điện 4 (mua 288,8 tỷ VND) và Công ty CP Xây lắp Điện 4 - Sông Hồng (mua 71,4 tỷ VND). Tổng mua hàng từ bên liên quan đạt 408,2 tỷ VND (tăng 89% so với năm trước). Phải trả người bán ngắn hạn cho bên liên quan lên tới 108,2 tỷ VND (tăng 73% so với đầu năm). Các giao dịch này có quy mô lớn, tuy nhiên chưa đủ bằng chứng để khẳng định có dấu hiệu bất thường về giá hay điều kiện giao dịch.', 'Tổng nợ phải trả (6.839 tỷ VND) vượt tổng tài sản (4.734 tỷ VND), vốn chủ sở hữu âm (-2.105 tỷ VND) cho thấy doanh nghiệp mất an toàn vốn nghiêm trọng. Nợ dài hạn chiếm chủ yếu với 3.599 tỷ VND, trong đó khoản nợ lớn nhất từ Bộ Tài chính (2.230 tỷ VND) đáo hạn 2027 và Ngân hàng PTKT Bắc Kạn-Thái Nguyên (1.285 tỷ VND) đáo hạn 2032. Chi phí lãi vay năm 2024 là 206,3 tỷ VND. Tài sản cố định trị giá 1.604 tỷ VND được dùng để thế chấp đảm bảo các khoản vay. Áp lực trả nợ rất lớn, đặc biệt khi hoạt động kinh doanh chính tạo ra lỗ gộp.', 'Chi phí sản xuất kinh doanh dở dang tăng mạnh từ 545,3 tỷ lên 713,6 tỷ VND (+31%), trong đó 62,63 tỷ VND chưa đánh giá được khả năng thu hồi do Công ty con vẫn đang làm việc với Chủ đầu tư về thanh quyết toán. Dự án Xi măng Quang Sơn lỗ nặng 490 tỷ VND trong năm 2024, cho thấy rủi ro lớn với lĩnh vực sản xuất xi măng. Hàng tồn kho tăng 23% so với đầu năm, đặt áp lực lên dòng tiền hoạt động.', 7, 'Tổng Công ty CP Xây dựng Công nghiệp Việt Nam (VVN) đang trong tình trạng tài chính khó khăn nghiêm trọng: vốn chủ sở hữu âm (-2.105 tỷ VND), lợi nhuận gộp âm (-3,8 tỷ VND), lỗ ròng hợp nhất -467,7 tỷ VND. Công ty con TNHH MTV Xi măng Quang Sơn là gánh nặng lớn nhất với lỗ 490 tỷ VND. Kiểm toán viên đã đưa ra ý kiến ngoại trừ do các khoản công nợ tồn đọng lớn (120 tỷ phải thu, 161 tỷ phải trả) và chi phí dở dang 62,63 tỷ chưa xác định được khả năng thu hồi. Tuy nhiên, hoạt động xây lắp vẫn có kết quả dương (lợi nhuận 119 tỷ VND) và doanh thu xây lắp tăng mạnh 116%. Triển vọng đầu tư tiêu cực trong ngắn hạn do mất an toàn vốn, rủi ro thanh khoản và phụ thuộc lớn vào nợ vay ưu đãi của Nhà nước.'),
('VVN_2023_consolidated', 'VVN', 2023, 'consolidated', 'Doanh nghiệp có lượng lớn giao dịch với các công ty con và công ty liên kết, đặc biệt phải thu từ Công ty Xi măng Quang Sơn lên tới hơn 381 tỷ VND (chiếm tỷ trọng lớn trong tài sản) và chi hộ lương cho công ty này. Các khoản phải thu, trả trước, và phải trả tập trung cao ở các bên liên quan, tiềm ẩn rủi ro thanh khoản và quản trị doanh nghiệp.', 'Áp lực nợ vay ngắn hạn ở mức vừa phải (~26,6 tỷ VND), có tài sản thế chấp là bất động sản trụ sở chính. Nợ dài hạn chủ yếu là nghĩa vụ trả quyền sử dụng đất theo phương án cổ phần hóa (chưa thanh toán), không phải nợ vay ngân hàng truyền thống.', 'Rủi ro tồn kho dở dang và dự án xây dựng dở dang ở mức cao, chiếm tỷ trọng lớn trong tài sản ngắn hạn. Nhiều dự án bất động sản, xây dựng cơ bản có giá trị lớn (Nhà máy điện LNG, Trung tâm Thương mại) có thể bị ảnh hưởng bởi thị trường bất động sản và tiến độ thi công. Dự phòng giảm giá hàng tồn kho đã được trích lập.', 6, 'Tổng Công ty có quy mô vốn lớn nhưng hoạt động kinh doanh chính (xây lắp) suy giảm mạnh về doanh thu và biên lợi nhuận gộp (~6%). Dòng tiền kinh doanh âm, doanh thu chủ yếu đến từ hoạt động tài chính (lãi vay, cổ tức từ công ty con). Điểm đáng lo ngại là cơ cấu tài sản tập trung vào các khoản phải thu lớn từ công ty con (Xi măng Quang Sơn) và các dự án xây dựng dở dang, gây áp lực lên thanh khoản và hiệu quả sử dụng vốn.'),
('VVN_2021_parent', 'VVN', 2021, 'parent', 'Rủi ro cao: Doanh nghiệp có giao dịch lớn với bên liên quan, đặc biệt khoản phải thu lên đến 374 tỷ VND với Công ty con Xi măng Quang Sơn và lãi vay 16,9 tỷ VND, thể hiện sự tập trung tín dụng vào một công ty con có hoạt động yếu kém (lỗ lớn, dự phòng đầu tư 200 tỷ). Các giao dịch mua bán, cho thuê với các công ty con/liên kết khác cũng đáng lưu ý.', 'Rủi ro thấp: Không có nợ vay ngân hàng tại cuối kỳ. Nợ phải trả chủ yếu là phải trả người bán (98 tỷ) và các khoản phải trả khác (34 tỷ), đã giảm so với đầu kỳ. Tuy nhiên, có khoản dự phòng bảo hành công trình 2,5 tỷ và phải nộp quyền sử dụng đất 13,4 tỷ từ cổ phần hóa.', 'Rủi ro trung bình: Hàng tồn kho tăng 20% so với đầu kỳ, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng mạnh (gấp đôi). Nhiều dự án đang triển khai (nâng cấp lưới điện, KCN, trung tâm thương mại) cần theo dõi tiến độ và khả năng thu hồi vốn.', 6, 'Tổng Công ty có kết quả kinh doanh cải thiện (lợi nhuận trước thuế tăng 24%) nhờ doanh thu xây lắp tăng. Tuy nhiên, sức khỏe tài chính tiềm ẩn nhiều rủi ro: (1) Phụ thuộc lớn vào các công ty con, đặc biệt Xi măng Quang Sơn với khoản đầu tư 200 tỷ đã trích lập toàn bộ dự phòng và khoản phải thu khổng lồ; (2) Hàng tồn kho dở dang tăng cao phản ánh nhiều dự án đang dang dở; (3) Không chia cổ tức, tập trung vào trích lập quỹ phúc lợi. Điểm tích cực là không có nợ vay ngân hàng và dòng tiền hoạt động kinh doanh dương.'),
('VVN_2022_consolidated', 'VVN', 2022, 'consolidated', 'Doanh nghiệp có giao dịch mua bán lớn với các công ty liên kết, trong đó có khoản vay không lãi suất từ Công ty CP Đầu tư và Phát triển Nguyễn Kim, cho thấy rủi ro về điều kiện giao dịch không công bằng và khả năng lợi ích nhóm.', 'Nợ vay cao với tổng nợ phải trả vượt tổng tài sản, vốn chủ sở hữu âm, chi phí lãi vay lớn, áp lực trả nợ nặng nề và rủi ro thanh khoản.', 'Tồn kho dở dang lớn, nhiều dự án xây dựng chưa hoàn thành và chưa được quyết toán, có khả năng bị ứ đọng và giảm giá trị.', 7, 'Tổng Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế, nợ vay cao, và ý kiến kiểm toán ngoại trừ. Triển vọng đầu tư không tích cực do rủi ro về quản trị, nợ và dự án dở dang.'),
('VVN_2021_consolidated', 'VVN', 2021, 'consolidated', 'Doanh nghiệp có giao dịch mua bán hàng hóa, dịch vụ và nhận cổ tức lớn với các công ty liên kết. Tổng giá trị giao dịch mua vào khoảng 174 tỷ VND và bán ra khoảng 126 tỷ VND năm 2021, cho thấy mức độ phụ thuộc vào các bên liên quan. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hoặc chênh lệch giá đáng ngờ.', 'Áp lực nợ vay rất cao với tổng nợ phải trả lên đến 5.940 tỷ VND, trong đó nợ ngắn hạn 2.472 tỷ VND và nợ dài hạn 3.468 tỷ VND. Công ty đang lỗ lũy kế và vốn chủ sở hữu âm, cho thấy rủi ro thanh toán lớn. Nhiều khoản vay được thế chấp bằng tài sản cố định và hàng tồn kho, nhưng khả năng trả nợ phụ thuộc vào hoạt động kinh doanh.', 'Hàng tồn kho và chi phí sản xuất kinh doanh dở dang có giá trị lớn (tổng cộng khoảng 843 tỷ VND tồn kho và 29 tỷ VND xây dựng cơ bản dở dang). Một số dự án xây dựng dở dang kéo dài, có thể ứ đọng và khó thu hồi vốn, đặc biệt dự án K2 Cầu Diễn được kiểm toán ngoại trừ về giá trị thanh toán.', 7, 'Tổng Công ty Cổ phần Xây dựng Công nghiệp Việt Nam đang trong tình trạng tài chính khó khăn với lỗ lũy kế, vốn chủ sở hữu âm và nợ vay cao. Kiểm toán ngoại trừ cho thấy rủi ro về công nợ và dự án dở dang. Tuy nhiên, doanh nghiệp vẫn hoạt động trong lĩnh vực xây lắp và sản xuất công nghiệp với doanh thu ổn định. Triển vọng đầu tư thận trọng do áp lực nợ và rủi ro quản trị.'),
('VVN_2020_parent', 'VVN', 2020, 'parent', 'Tổng Công ty có giao dịch phức tạp với hệ sinh thái các công ty con và liên kết. Đặc biệt đáng chú ý: (1) Khoản phải thu Công ty TNHH MTV Xi măng Quang Sơn lên đến 319 tỷ VNĐ - là khoản Tổng Công ty trả nợ thay cho dự án Nhà máy Xi măng Thái Nguyên cho Ngân hàng BNP Paribas, cho thấy rủi ro tài chính lớn từ dự án đầu tư không hiệu quả; (2) Đầu tư 200 tỷ VNĐ vào Công ty TNHH MTV Xi măng Quang Sơn đã trích lập dự phòng 100%; (3) Nhiều khoản phải thu, trả trước lớn với các công ty con/liên kết (phải thu ngắn hạn khác từ bên liên quan 353 tỷ VNĐ, trả trước cho người bán là bên liên quan 15,7 tỷ VNĐ); (4) Doanh thu xây lắp từ bên liên quan chiếm tỷ trọng nhỏ nhưng giao dịch mua hàng từ bên liên quan rất lớn (18,5 tỷ VNĐ). Rủi ro tập trung vào việc Tổng Công ty phải gánh chịu nghĩa vụ tài chính thay cho các công ty con hoạt động kém hiệu quả.', 'Áp lực nợ vay ngắn hạn ở mức vừa phải với dư nợ 9,556 tỷ VNĐ (giảm từ 13,264 tỷ VNĐ đầu năm). Hợp đồng tín dụng hạn mức 70 tỷ VNĐ với BIDV có tài sản thế chấp là tòa nhà Vinaincon - tài sản cốt lõi của Tổng Công ty. Dòng tiền hoạt động kinh doanh năm 2020 âm (-5,4 tỷ VNĐ), bù đắp chủ yếu từ hoạt động đầu tư (26,6 tỷ VNĐ thu từ cổ tức, lãi vay). Chi phí lãi vay giảm mạnh từ 1,2 tỷ xuống 120 triệu VNĐ. Tổng Công ty có vay cá nhân 93 triệu VNĐ. Dự phòng nợ phải thu khó đòi giảm từ 64,8 tỷ xuống 60,3 tỷ VNĐ.', 'Hàng tồn kho giảm nhẹ từ 66,5 tỷ xuống 64,1 tỷ VNĐ, chủ yếu do giảm chi phí sản xuất dở dang (từ 64,6 tỷ xuống 38,6 tỷ VNĐ) - cho thấy một số công trình đã hoàn thành. Nguyên vật liệu tăng mạnh từ 1,9 tỷ lên 25,3 tỷ VNĐ, phản ánh hoạt động mua sắm nguyên liệu cho các dự án mới. Dự phòng giảm giá hàng tồn kho duy trì ở mức 76,5 triệu VNĐ. Tỷ lệ chi phí sản xuất dở dang chiếm 60% tổng hàng tồn kho, đặt ra rủi ro nếu các dự án chậm tiến độ hoặc phát sinh chi phí vượt dự toán.', 6, 'Tổng Công ty Cổ phần Xây dựng Công nghiệp Việt Nam (VINAINCON) năm 2020 đạt doanh thu thuần 313,7 tỷ VNĐ (tăng 2,9% so với năm 2019), tuy nhiên hoạt động xây lắp chính bị lỗ gộp 832 triệu VNĐ (do giá vốn 314,2 tỷ vượt doanh thu 313,3 tỷ). Lợi nhuận trước thuế đạt 13,2 tỷ VNĐ (giảm 22,5%) chủ yếu nhờ doanh thu tài chính (48,5 tỷ từ lãi tiền gửi, cổ tức được chia) và thu nhập khác (4 tỷ). Tổng tài sản tăng 12,2% lên 987,8 tỷ VNĐ, vốn chủ sở hữu đạt 709,6 tỷ VNĐ. Rủi ro lớn nhất là hệ thống công ty con hoạt động không hiệu quả: Xi măng Quang Sơn lỗ nặng (dự phòng 200 tỷ), Cơ khí Hóa chất Hà Bắc (dự phòng 100 tỷ), nhiều công ty con khác cũng phải trích lập dự phòng. Tổng dự phòng đầu tư tài chính dài hạn lên đến 234 tỷ VNĐ (tăng 7,6 tỷ so với đầu năm). Công ty có 128 nhân viên, giảm từ 150 người. Ban lãnh đạo có thay đổi Tổng Giám đốc giữa năm. Triển vọng đầu tư thận trọng do lỗ gộp từ hoạt động xây lắp chính, rủi ro tài chính từ hệ sinh thái công ty con, và sự phụ thuộc lớn vào thu nhập tài chính từ cổ tức công ty con/liên kết.'),
('VVN_2020_consolidated', 'VVN', 2020, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan trong năm 2020: doanh thu bán hàng cho bên liên quan đạt 156,9 tỷ đồng, mua hàng từ bên liên quan 151,4 tỷ đồng. Đáng chú ý, Công ty TNHH MTV Xây lắp Điện 2 (công ty con 100%) cho Công ty CP Tư vấn và Đầu tư Phát triển Phước Long (công ty liên kết gián tiếp) vay 76,7 tỷ đồng với lãi suất 0%/tháng theo hợp đồng vay năm 2016, chưa có kế hoạch trả nợ cụ thể. Giao dịch mua bán với Công ty CP Khai thác Đá vôi Quang Sơn và Công ty CP Bao bì Sông Công có giá trị hàng trăm tỷ đồng cần được xem xét tính hợp lý về giá cả. Mạng lưới công ty con và liên kết phức tạp tạo ra rủi ro lợi ích xung đột.', 'Tổng nợ vay lên tới 4.111 tỷ đồng trong khi vốn chủ sở hữu âm 720 tỷ đồng, cho thấy áp lực nợ rất nghiêm trọng. Công ty TNHH MTV Xi măng Quang Sơn (công ty con) nợ quá hạn khoảng 675 tỷ đồng tiền gốc và lãi vay ưu đãi của Bộ Tài chính và Ngân hàng Phát triển khu vực Bắc Kạn - Thái Nguyên. Tiền và tương đương tiền chỉ 259 tỷ đồng không đủ để trang trải nợ ngắn hạn 636 tỷ đồng. Tài sản cố định trị giá 2.378 tỷ đồng đã được đem thế chấp cho các khoản vay ngân hàng.', 'Chi phí xây dựng cơ bản dở dang giảm từ 31,4 tỷ xuống 30,2 tỷ đồng, không có dấu hiệu ứ đọng nghiêm trọng. Tuy nhiên, kiểm toán viên chưa thu thập đủ bằng chứng để đánh giá khả năng thu hồi 79,9 tỷ đồng chi phí SXKD dở dang của các công ty con không thay đổi qua nhiều năm. Dự án 119 K2 Cầu Diễn có rủi ro do khoản đề nghị bổ sung 27,7 tỷ đồng chưa được chủ đầu tư chấp thuận. Dự phòng giảm giá hàng tồn kho giảm từ 923 triệu xuống 123 triệu đồng, cho thấy hàng tồn kho đã được đánh giá lại.', 7, 'Tổng Công ty CP Xây dựng Công nghiệp Việt Nam đang trong tình trạng tài chính rất khó khăn: vốn chủ sở hữu âm 720 tỷ đồng, lỗ lũy kế 1.573 tỷ đồng, báo cáo kiểm toán bị ngoại trừ do nhiều vấn đề chưa được xác nhận (công nợ phải thu/trả, chi phí dở dang). Tuy nhiên, doanh nghiệp vẫn tạo ra doanh thu thuần hợp nhất 4.570 tỷ đồng, lợi nhuận gộp 348 tỷ đồng và dòng tiền hoạt động kinh doanh dương 197 tỷ đồng. Lỗ lớn chủ yếu đến từ Công ty TNHH MTV Xi măng Quang Sơn (lỗ 221 tỷ đồng) và chi phí tài chính cao (lãi vay 163 tỷ + lỗ chênh lệch tỷ giá 100 tỷ). Nếu loại bỏ ảnh hưởng của Xi măng Quang Sơn, lợi nhuận sau thuế là 47,2 tỷ đồng. Công ty có mạng lưới công ty con và liên kết rộng lớn nhưng cần cải thiện quản trị, minh bạch giao dịch với bên liên quan, và xử lý nợ quá hạn tại Xi măng Quang Sơn để cải thiện tình hình tài chính.'),
('VVN_2019_consolidated', 'VVN', 2019, 'consolidated', 'Công ty có cấu trúc sở hữu phức tạp với 13 công ty con và 12 công ty liên kết/liên doanh. Các giao dịch với bên liên quan bao gồm mua bán hàng hóa dịch vụ (635 triệu VND với công ty liên kết E&C), các khoản phải thu, trả trước và phải trả với các bên liên quan lên đến hàng trăm tỷ đồng. Mối quan hệ chồng chéo giữa các công ty trong hệ thống tạo rủi ro về tính minh bạch và giá chuyển nhượng. Công ty con Xi măng Quang Sơn lỗ nặng 126.6 tỷ VND, ảnh hưởng nghiêm trọng đến kết quả hợp nhất.', 'Áp lực nợ vay rất lớn với tổng nợ vay và nợ thuê tài chính hơn 4,095 tỷ VNĐ (ngắn hạn 657.7 tỷ, dài hạn 3,437.3 tỷ). Nợ dài hạn chủ yếu từ Bộ Tài chính (1,903.6 tỷ), Ngân hàng Phát triển (1,064.7 tỷ) liên quan đến khoản vay của Công ty Xi măng Quang Sơn đã được tái cơ cấu. Vốn chủ sở hữu hợp nhất âm 504.9 tỷ VND, cho thấy công ty hoạt động dựa hoàn toàn vào nợ. Chi phí lãi vay năm 2019 là 154.9 tỷ VND. Tài sản thế chấp chi tiết không được thuyết minh rõ ràng trong báo cáo.', 'Hàng tồn kho lớn 880.6 tỷ VND với dự phòng giảm giá chỉ 923 triệu VND (rất nhỏ so với giá trị). Chi phí SXKD dở dang 533.5 tỷ VND không có dự phòng, trong đó có công trình đường dây 220KV có dấu hiệu suy giảm giá trị 41.8 tỷ VND nhưng chưa được trích lập dự phòng do chưa quyết toán. Dự án 119 K2 Cầu Diễn có chi phí dở dang 16.3 tỷ VND cũng chưa có dự phòng. Công ty TNHH MTV Xây lắp Điện 2 hoàn nhập toàn bộ dự phòng bảo hành 30.14 tỷ VND, gây lo ngại về tính đầy đủ của dự phòng.', 8, 'Tổng Công ty VINAINCON đang trong tình trạng tài chính rất khó khăn: lỗ sau thuế 118.2 tỷ VND năm 2019 (cải thiện so với lỗ 282.5 tỷ năm 2018), vốn chủ sở hữu âm 504.9 tỷ VND, hoạt động dựa hoàn toàn vào vốn vay. Công ty con Xi măng Quang Sơn lỗ nặng 126.6 tỷ VND và được tái cơ cấu nợ với sự hỗ trợ của Chính phủ. Kiểm toán đưa ra ý kiến ngoại trừ do không thu thập đủ bằng chứng về các khoản phải thu 117.1 tỷ, phải trả 121.7 tỷ, và dự phòng bảo hành, tồn kho. Điểm sáng là doanh thu thuần tăng 29% lên 4,348 tỷ VND, dòng tiền từ hoạt động kinh doanh dương 91.5 tỷ VND. Tuy nhiên, rủi ro phá sản và ngừng hoạt động liên tục là hiện hữu nếu không có sự hỗ trợ từ Chính phủ và chủ nợ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VXP_2023_consolidated', 'VXP', 2023, 'consolidated', 'Giao dịch với bên liên quan chỉ bao gồm lương thưởng cho ban lãnh đạo, không có giao dịch bất thường hoặc đáng ngờ.', 'Nợ vay ngắn hạn chỉ 200 triệu VNĐ, áp lực nợ thấp, khả năng thanh toán tốt.', 'Tồn kho cao, đặc biệt thành phẩm và hàng hoá, có trích lập dự phòng giảm giá lớn cho sản phẩm vắc xin, cho thấy rủi ro ứ đọng hàng tồn kho do vấn đề nguồn cung.', 3, 'Công ty lỗ ròng lớn trong năm 2023 do doanh thu giảm mạnh (gần 42%) và trích lập dự phòng tồn kho. Nợ vay thấp nhưng tồn kho cao gây rủi ro tài chính. Triển vọng phụ thuộc vào việc giải quyết vấn đề nguồn cung từ nhà cung cấp chính và tiêu thụ hàng tồn kho.'),
('VVN_2018_parent', 'VVN', 2018, 'parent', 'Có nhiều giao dịch và số dư lớn với các bên liên quan, đặc biệt khoản phải thu khác từ Công ty TNHH MTV Xi măng Quang Sơn (công ty con) lên tới 294.292.594.985 VND, do Tổng Công ty đứng ra bảo lãnh vay vốn ngân hàng. Nhiều khoản đầu tư vào công ty con và liên kết đã trích lập dự phòng lớn (tổng dự phòng đầu tư tài chính dài hạn hơn 225 tỷ). Có rủi ro về hiệu quả quản trị và khả năng thu hồi vốn từ các bên liên quan.', 'Nợ vay ngắn hạn tăng mạnh từ 3.426.510.019 VND lên 38.770.318.565 VND, tập trung chủ yếu vào vay từ Ngân hàng TMCP Đầu tư và Phát triển Việt Nam. Tổng Công ty có hạn mức tín dụng 365 tỷ VND và dư nợ/bảo lãnh/L/C tối đa 110 tỷ VND. Áp lực trả nợ ngắn hạn tăng cao, tuy nhiên tài sản đảm bảo đa dạng bao gồm tiền gửi, phải thu từ dự án, hàng tồn kho và tài sản cố định.', 'Hàng tồn kho tăng từ 44.829.928.131 VND lên 68.325.676.032 VND, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng mạnh (từ 43,4 tỷ lên 65,9 tỷ). Điều này cho thấy có nhiều công trình xây dựng đang triển khai dở dang, cần theo dõi tiến độ và khả năng thu hồi chi phí. Dự phòng giảm giá hàng tồn kho chỉ 76.560.000 VND, mức thấp.', 7, 'Tổng Công ty có kết quả kinh doanh cải thiện so với năm trước (lợi nhuận trước thuế 16,7 tỷ, năm trước 17,3 tỷ). Tuy nhiên, cấu trúc tài chính có nhiều điểm đáng lo ngại: (1) Nợ ngắn hạn tăng vọt trong khi tiền mặt chỉ đạt 22,8 tỷ; (2) Các khoản phải thu và đầu tư vào công ty con có nhiều khoản nợ xấu hoặc đã trích lập dự phòng lớn, đặc biệt là Công ty Xi măng Quang Sơn; (3) Hàng tồn kho dở dang tăng mạnh. Doanh thu giảm 52% so với năm trước nhưng biên lợi nhuận gộp cải thiện. Doanh thu chủ yếu từ hoạt động xây lắp. Công ty có mạng lưới công ty con, liên kết rộng nhưng hiệu quả quản trị và kiểm soát rủi ro cần được cải thiện.'),
('VVN_2019_parent', 'VVN', 2019, 'parent', 'Công ty có giao dịch lớn với các công ty con và liên kết, đặc biệt là Công ty TNHH MTV Xi măng Quang Sơn với doanh số mua hàng và lãi vay chi hộ cao, tiềm ẩn rủi ro về giá cả và xung đột lợi ích.', 'Nợ vay chủ yếu là ngắn hạn với tổng số tiền khoảng 130 tỷ VNĐ, áp lực nợ thấp nhưng dòng tiền hoạt động âm, cần theo dõi khả năng thanh toán.', 'Hàng tồn kho bao gồm chi phí sản xuất dở dang lớn (hơn 646 tỷ VNĐ), có thể do dự án xây dựng chậm tiến độ hoặc vượt chi phí, rủi ro giảm giá trị.', 6, 'Doanh nghiệp có lợi nhuận ổn định nhưng dòng tiền hoạt động kinh doanh âm do tăng phải thu và tồn kho. Nợ vay ngắn hạn an toàn, nhưng phụ thuộc vào cổ tức từ công ty con. Triển vọng trung bình, cần cải thiện quản lý vốn lưu động và giảm rủi ro từ giao dịch liên quan.'),
('VUG_2025_consolidated', 'VUG', 2025, 'consolidated', 'Doanh nghiệp có giao dịch mua hàng hóa và dịch vụ lớn từ công ty liên kết (Công ty TNHH Việt Úc Thức ăn Thủy sản) với giá trị hơn 54,9 tỷ VNĐ, chiếm tỷ trọng đáng kể trong chi phí. Cần đánh giá tính công bằng của giá cả và điều kiện giao dịch so với thị trường.', 'Nợ vay ngắn hạn tăng mạnh từ 19,1 tỷ lên 44,1 tỷ VNĐ, chủ yếu phục vụ vốn lưu động. Tài sản thế chấp bao gồm quyền sử dụng đất và tiền gửi có kỳ hạn. Áp lực trả nợ trong ngắn hạn ở mức vừa phải, dòng tiền kinh doanh mạnh có thể hỗ trợ.', 'Hàng tồn kho giảm từ 166,3 tỷ xuống 138,4 tỷ VNĐ, dự phòng giảm giá cũng giảm từ 8,4 tỷ xuống 3,8 tỷ VNĐ, cho thấy kiểm soát tồn kho được cải thiện. Tuy nhiên, vẫn có chi phí sản xuất dở dang và thành phẩm tồn kho cần theo dõi.', 6, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng mạnh, lợi nhuận sau thuế tăng gần 4 lần. Dòng tiền hoạt động kinh doanh dương mạnh. Tuy nhiên, cần lưu ý giao dịch bên liên quan có giá trị lớn, nợ vay ngắn hạn tăng, và nhiều khoản đầu tư vào dự án đang xây dựng dở dang. Quản trị ở mức trung bình do có nhiều giao dịch với bên liên quan và cơ cấu sở hữu phức tạp.'),
('VVN_2017_parent', 'VVN', 2017, 'parent', 'Doanh nghiệp có nhiều giao dịch mua bán và nhận cổ tức với các công ty con, công ty liên kết với giá trị lớn, đặc biệt giao dịch mua hàng từ Công ty CP TV Thiết kế và XD VINAINCON (hơn 72 tỷ VND). Cần kiểm soát chặt chẽ để tránh giao dịch không công bằng hoặc chuyển giá.', 'Nợ vay ngắn hạn chỉ khoảng 3,4 tỷ VND, chiếm tỷ trọng nhỏ trong tổng tài sản, áp lực trả nợ thấp. Doanh nghiệp có hạn mức tín dụng 30 tỷ VND với lãi suất thỏa thuận và tài sản bảo đảm theo hợp đồng.', 'Hàng tồn kho giảm mạnh từ 97,1 tỷ VND xuống còn 44,8 tỷ VND, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang (từ 88,9 tỷ xuống 43,4 tỷ). Điều này cho thấy các dự án xây dựng đã được đẩy nhanh tiến độ, giảm nguy cơ ứ đọng.', 5, 'Tổng Công ty có cơ cấu tài chính tương đối lành mạnh với tỷ lệ nợ thấp. Tuy nhiên, doanh thu và lợi nhuận giảm mạnh so với năm trước (doanh thu giảm 33%, lợi nhuận giảm 29%). Doanh nghiệp phụ thuộc lớn vào hoạt động xây lắp và có mạng lưới giao dịch phức tạp với các bên liên quan. Điểm mạnh là hàng tồn kho giảm và dòng tiền từ hoạt động kinh doanh dương. Cần cải thiện hiệu quả kinh doanh và quản lý rủi ro từ các khoản đầu tư vào công ty con, liên kết.'),
('VVN_2016_parent', 'VVN', 2016, 'parent', 'Tổng Công ty có nhiều giao dịch mua bán, nhận cổ tức/lợi nhuận được chia và cho vay với các công ty con, công ty liên kết. Giá trị giao dịch lớn, đặc biệt là mua hàng (244 tỷ) và nhận cổ tức/lợi nhuận (43 tỷ). Rủi ro nằm ở tính công bằng của giá cả và điều khoản giao dịch giữa các bên, nhưng thuyết minh không cung cấp đủ chi tiết để đánh giá mức độ bất thường cụ thể.', 'Nợ vay ngắn hạn tăng mạnh từ 91 triệu lên 18,3 tỷ VND, chủ yếu từ Ngân hàng TMCP Đầu tư và Phát triển Việt Nam. Áp lực nợ ngắn hạn tăng, nhưng tổng giá trị nợ vay vẫn thấp so với tài sản. Không có tài sản thế chấp nổi bật được ghi nhận.', 'Tồn kho tăng 59% (từ 61 tỷ lên 97 tỷ), chủ yếu là chi phí sản xuất kinh doanh dở dang (tăng 49%). Các công trình dở dang lớn (Nhà máy gang thép Thái Nguyên, Nhiệt điện Vĩnh Tân 4...) có thể tiềm ẩn rủi ro chậm tiến độ hoặc vượt dự toán, nhưng không có trích lập dự phòng giảm giá.', 6, 'Tổng Công ty duy trì hoạt động kinh doanh với doanh thu thuần 563 tỷ VND, lợi nhuận sau thuế 26 tỷ VND. Tuy nhiên, dòng tiền hoạt động kinh doanh âm lớn (-133 tỷ) do tăng mạnh hàng tồn kho và phải thu. Điểm đáng lo ngại là ý kiến kiểm toán ngoại trừ liên quan đến khoản đầu tư lớn vào Công ty TNHH MTV Xi măng Quang Sơn (200 tỷ giá gốc) và việc trích lập dự phòng chưa đầy đủ. Công ty có nhiều giao dịch nội bộ phức tạp. Triển vọng phụ thuộc vào khả năng thu hồi các khoản đầu tư, quản lý dòng tiền và xử lý các vấn đề tồn đọng.'),
('VUG_2025_parent', 'VUG', 2025, 'parent', 'Doanh nghiệp có nhiều giao dịch mua bán hàng hóa, dịch vụ nội bộ giữa công ty mẹ và các công ty con trong hệ sinh thái thủy sản. Các giao dịch này có quy mô lớn và chiếm tỷ trọng đáng kể trong doanh thu và chi phí, tuy nhiên được thuyết minh rõ ràng và dường như là giao dịch thương mại thông thường. Có các khoản cho vay ngắn hạn cho công ty con (1.1 tỷ VNĐ) nhưng không rõ điều kiện lãi suất, có thể tiềm ẩn rủi ro về giá chuyển nhượng không theo giá thị trường.', 'Nợ vay ngắn hạn tăng mạnh từ 4.19 tỷ lên 29.8 tỷ VNĐ trong năm, chủ yếu để bổ sung vốn lưu động. Các khoản vay được thế chấp bằng tài sản (quyền sử dụng đất và tiền gửi có kỳ hạn) và có lãi suất biến động (2.8% - 7.3%/năm). Áp lực trả nợ ở mức trung bình do tài sản thế chấp充足 và kỳ hạn tương đối ngắn.', 'Hàng tồn kho giảm từ 17.94 tỷ xuống 11.27 tỷ VNĐ, chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang, cho thấy hiệu quả quản lý tồn kho tốt. Dự án xây dựng dở dang tăng mạnh từ 24.09 tỷ lên 78.28 tỷ VNĐ, tập trung vào các dự án công nghệ cải thiện di truyền tôm, đây là đầu tư chiến lược nhưng cần theo dõi tiến độ và khả năng hoàn thành.', 5, 'Công ty có kết quả kinh doanh tích cực với doanh thu thuần tăng nhẹ và biên lợi nhuận gộp ổn định khoảng 44.4%. Tuy nhiên, dòng tiền hoạt động kinh doanh âm (-101.5 tỷ) do tăng mạnh đầu tư vào xây dựng dở dang và giảm các khoản phải trả. Nợ vay tăng nhưng có tài sản thế chấp. Công ty đang trong giai đoạn mở rộng mạnh mẽ với nhiều dự án công nghệ mới, triển vọng phụ thuộc vào khả năng triển khai hiệu quả các dự án này. Cấu trúc sở hữu phức tạp với nhiều công ty con và giao dịch nội bộ lớn cần được giám sát.'),
('VUG_2024_parent', 'VUG', 2024, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty con và công ty liên kết, chủ yếu là mua bán hàng hóa, dịch vụ và chia cổ tức. Các giao dịch này có vẻ minh bạch và theo giá thị trường, nhưng tần suất cao có thể cần giám sát để đảm bảo không có xung đột lợi ích.', 'Công ty chỉ có một khoản vay ngắn hạn với ngân hàng, lãi suất cố định 5%/năm, có tài sản thế chấp, và đáo hạn trong thời gian ngắn. Áp lực nợ thấp, khả năng thanh toán tốt.', 'Hàng tồn kho bao gồm nguyên vật liệu và sản phẩm dở dang, không có dự phòng. Dự án xây dựng dở dang liên quan đến phát triển công nghệ tôm, có thể bị ảnh hưởng bởi tiến độ triển khai và nhu cầu thị trường.', 5, 'Công ty hoạt động trong ngành thủy sản với biên lợi nhuận gộp cao khoảng 47%, lợi nhuận sau thuế ổn định. Tuy nhiên, dòng tiền hoạt động kinh doanh âm do tăng trưởng đầu tư. Công ty có hệ thống công ty con rộng lớn, cần quản trị tốt để tránh rủi ro tập trung. Triển vọng trung bình đến tích cực nếu quản lý hiệu quả.'),
('VUG_2024_consolidated', 'VUG', 2024, 'consolidated', 'Tập đoàn có mạng lưới công ty của cổ đông rộng lớn với hơn 15 công ty liên kết/công ty của cổ đông. Giao dịch mua hàng hóa và dịch vụ với bên liên quan đạt 20,45 tỷ VND trong năm 2024 (trong đó Công ty TNHH Việt Úc Thức ăn Thủy sản - công ty liên kết chiếm 19,7 tỷ VND), tăng gấp đôi so với năm 2023 (9,49 tỷ VND). Doanh thu bán hàng cho bên liên quan chỉ đạt 8,7 triệu VND. Có khoản phải thu dài hạn 3,94 tỷ VND từ Công ty TNHH Dịch vụ và Xây dựng Việt Úc (công ty của cổ đông) phát sinh từ chi hộ. Tuy nhiên, các khoản dư nợ với bên liên quan đều có giá trị tương đối nhỏ so với tổng tài sản, và BCTC đã trình bày đầy đủ.', 'Nợ vay rất thấp so với tổng tài sản. Chỉ có vay ngắn hạn 19,19 tỷ VND (0,86% tổng tài sản), không có vay dài hạn. Lãi suất vay 5%/năm, đáo hạn trong 2025. Tiền mặt và tương đương tiền đạt 175,85 tỷ VND, gấp 9,17 lần tổng nợ vay. Tuy nhiên, Tập đoàn đã chi 253,8 tỷ VND cổ tức trong năm 2024 làm giảm mạnh tiền mặt từ 299 tỷ xuống 176 tỷ VND. Chi phí lãi vay chỉ 297 triệu VND, áp lực nợ vay không đáng kể.', 'Hàng tồn kho đạt 166,39 tỷ VND (giá trị ghi sổ). Dự phòng giảm giá hàng tồn kho là 8,49 tỷ VND, trong đó dự phòng cho thành phẩm chiếm 5,85 tỷ VND và hàng dở dang chiếm 2,64 tỷ VND, phản ánh rủi ro chậm lưu chuyển và giảm giá. Chi phí xây dựng cơ bản dở dang rất lớn (257,47 tỷ VND) tập trung vào các dự án trại sản xuất tôm, công nghệ giống cá tra, nhà máy chế biến thủy sản. Giá trị CIP giảm từ 388 tỷ xuống 257 tỷ VND do chuyển sang TSCĐ, cho thấy tiến độ triển khai dự án tích cực.', 5, 'Công ty Cổ phần Thủy Sản Việt Úc có nền tảng tài chính vững mạnh với tỷ lệ nợ vay/tổng tài sản chỉ 0,86% và tiền mặt dồi dào (175,85 tỷ VND). Biên lợi nhuận gộp đạt 49,06%, phản ánh năng lực sinh lời tốt từ hoạt động kinh doanh cốt lõi (tôm giống, tôm thương phẩm, tôm chế biến). Tuy nhiên, LNST giảm 13% so với năm trước (32,29 tỷ vs 37,20 tỷ VND) do chi phí bán hàng và quản lý tăng. Công ty đang tích cực đầu tư mở rộng năng lực sản xuất qua các dự án xây dựng lớn (257 tỷ VND CIP). Rủi ro chính là: (1) mạng lưới giao dịch với công ty của cổ đông rộng lớn; (2) khoản đầu tư vào công ty liên kết đang lỗ lũy kế (giảm từ 54,57 tỷ xuống 35,30 tỷ VND); (3) chi trả cổ tức lớn (253,8 tỷ VND) làm giảm mạnh tiền mặt; (4) một số công ty con trong giai đoạn xây dựng chưa tạo doanh thu. Triển vọng trung hạn phụ thuộc vào khả năng hoàn thiện các dự án đầu tư và cải thiện hiệu quả kinh doanh của công ty liên kết.'),
('VUG_2023_consolidated', 'VUG', 2023, 'consolidated', 'Giao dịch với các bên liên quan bao gồm bán hàng, mua hàng, chi trả thù lao cho ban lãnh đạo và chia cổ tức cho cổ đông. Các giao dịch này dường như là giao dịch thương mại thông thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, có một khoản đầu tư vào công ty liên kết là Công ty TNHH Việt Úc Thức ăn Thủy sản và giao dịch chi hộ giữa các công ty con, nhưng mức giá trị không đáng kể.', 'Nợ phải trả của Tập đoàn tương đối thấp so với tổng tài sản. Nợ ngắn hạn là 138,459,047,017 VND và nợ dài hạn là 23,316,817,594 VND, chủ yếu là dự phòng phải trả dài hạn. Không có thông tin chi tiết về lãi suất hay tài sản thế chấp, nhưng dựa trên tỷ lệ nợ thấp, áp lực nợ vay không đáng lo ngại.', 'Hàng tồn kho có dự phòng giảm giá 8,609,316,618 VND vào cuối năm 2023, giảm so với năm trước. Chi phí xây dựng cơ bản dở dang lớn (388,020,621,373 VND), cho thấy Tập đoàn đang đầu tư mạnh vào tài sản cố định, có thể tiềm ẩn rủi ro nếu dự án bị chậm trễ hoặc không hiệu quả.', 4, 'Tập đoàn Thủy sản Việt Úc có tình hình tài chính ổn định với tỷ lệ nợ thấp và dòng tiền hoạt động kinh doanh dương. Doanh thu và lợi nhuận năm 2023 giảm so với năm trước, nhưng công ty tiếp tục đầu tư vào mở rộng sản xuất. Triển vọng trung lập, cần theo dõi hiệu quả của các dự án đầu tư mới.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VUG_2023_parent', 'VUG', 2023, 'parent', 'Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm cho vay không lãi suất và tín chấp, mua bán hàng hóa giá trị lớn. Điều này có thể gây rủi ro về tính công bằng của giao dịch và dòng tiền, đặc biệt khi các khoản vay không có lãi suất.', 'Nợ phải trả chủ yếu là nợ ngắn hạn thương mại (phải trả người bán, thuế, lương) và dự phòng dài hạn. Không có thông tin chi tiết về nợ vay ngân hàng hay lãi suất, nên áp lực nợ vay không rõ ràng. Tuy nhiên, nợ ngắn hạn tăng mạnh, cần theo dõi khả năng thanh toán.', 'Hàng tồn kho và chi phí xây dựng cơ bản dở dang tăng so với năm trước. Dự án phát triển tôm thể chân trắng giai đoạn 3 có giá trị lớn, có thể tiềm ẩn rủi ro ứ đọng nếu dự án chậm tiến độ.', 6, 'Công ty hoạt động trong lĩnh vực thủy sản, doanh thu giảm so với năm trước nhưng lợi nhuận vẫn dương. Có mạng lưới công ty con rộng lớn và giao dịch nội bộ phức tạp. Dòng tiền từ hoạt động đầu tư và tài chính mạnh, nhưng rủi ro liên quan đến giao dịch bên liên quan và nợ ngắn hạn cần được giám sát.'),
('VUG_2022_consolidated', 'VUG', 2022, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan bao gồm công ty liên kết và công ty của cổ đông. Có khoản cho vay không lãi suất, không tài sản đảm bảo cho Công ty CP Việt Úc - Ngọc Hiển. Có giao dịch mua bán tài sản cố định với công ty liên kết. Có khoản góp vốn đầu tư lớn vào công ty liên kết đang lỗ. Có giao dịch mua lại cổ phần của cổ đông tại công ty con mới với giá trị lớn. Các giao dịch này tiềm ẩn rủi ro xung đột lợi ích và thiếu minh bạch.', 'Nợ phải trả chủ yếu là nợ ngắn hạn từ hoạt động kinh doanh (phải trả người bán, người lao động, thuế). Có khoản vay ngắn hạn và dài hạn từ việc mua công ty con mới (Công ty CP Việt Úc - Ngọc Hiển). Tổng nợ phải trả chiếm tỷ trọng nhỏ trong tổng nguồn vốn (khoảng 8%), áp lực nợ không lớn. Tuy nhiên, công ty có nhiều cam kết vốn đầu tư lớn cho các dự án xây dựng.', 'Hàng tồn kho có dự phòng giảm giá cho chi phí sản xuất dở dang (9,9 tỷ VNĐ). Có nhiều dự án xây dựng cơ bản dở dang với giá trị lớn (557,7 tỷ VNĐ) tập trung vào nhà máy chế biến thủy sản, khu sản xuất tôm và dự án phát triển công nghệ. Cần theo dõi tiến độ và khả năng hoàn thành các dự án này.', 7, 'Doanh thu thuần giảm nhẹ (3.5%) trong khi lợi nhuận sau thuế giảm mạnh (38.7%) do lỗ từ công ty liên kết và chi phí khác tăng. Biên lợi nhuận gộp vẫn duy trì ở mức cao (56.4%). Công ty đang mở rộng sản xuất mạnh mẽ với nhiều dự án xây dựng dở dang. Nợ phải trả ở mức an toàn. Tuy nhiên, cần lưu ý rủi ro từ giao dịch bên liên quan, hiệu quả đầu tư vào công ty liên kết, và khả năng hoàn thành các dự án xây dựng lớn.'),
('VUG_2022_parent', 'VUG', 2022, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty con, công ty liên kết và công ty của cổ đông. Các khoản cho vay với công ty trong Tập đoàn là tín chấp, không lãi suất, tiềm ẩn rủi ro về quản trị và xung đột lợi ích. Tổng cho vay ngắn hạn bên liên quan lên đến 56.95 tỷ VNĐ năm 2022.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán, thuế, người lao động và dự phòng dài hạn. Tỷ lệ nợ ngắn hạn cao (52.19 tỷ VNĐ) so với tài sản ngắn hạn, nhưng Công ty có lượng tiền mặt lớn (30.51 tỷ VNĐ) và đầu tư ngắn hạn (22 tỷ VNĐ) nên khả năng thanh toán vẫn đảm bảo. Không có tài sản thế chấp do không vay ngân hàng.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và sản phẩm dở dang, không có dự phòng giảm giá. Chi phí xây dựng cơ bản dở dang lớn (33.29 tỷ VNĐ) cho các dự án nghiên cứu phát triển giống tôm và công nghệ mới, đây là các dự án dài hạn có thể mang lại giá trị trong tương lai nhưng cũng có rủi ro không thành công.', 7, 'Công ty có kết quả kinh doanh tốt với doanh thu thuần 265.9 tỷ VNĐ và lợi nhuận sau thuế 589.5 tỷ VNĐ năm 2022, tăng mạnh so với năm 2021. Tuy nhiên, lợi nhuận chủ yếu đến từ doanh thu hoạt động tài chính (cổ tức từ công ty con) chứ không phải từ hoạt động kinh doanh chính. Công ty đầu tư mạnh vào nghiên cứu phát triển công nghệ mới, có tiềm năng tăng trưởng nhưng cũng chứa đựng rủi ro. Quản trị doanh nghiệp có mức rủi ro cao do giao dịch bên liên quan phức tạp và việc cho vay tín chấp, không lãi suất cho các công ty trong Tập đoàn.'),
('VUG_2020_consolidated', 'VUG', 2020, 'consolidated', 'Có rủi ro đáng kể. Công ty cho vay không lãi suất, không tài sản đảm bảo tới công ty liên quan (Ngọc Hiển, Dịch vụ Thương mại Xây dựng Việt Úc). Các giao dịch mua bán, chi hộ với công ty liên quan có thể không phản ánh giá thị trường.', 'Rủi ro nợ thấp. Công ty chủ yếu vay không lãi suất từ bên liên quan, không có áp lực trả lãi ngân hàng. Tài sản thế chấp không yêu cầu cho khoản vay liên quan.', 'Rủi ro trung bình. Hàng tồn kho có dự phòng giảm giá (833 triệu VND), chủ yếu là chi phí sản xuất dở dang. Dự án xây dựng cơ bản dở dang lớn (374 tỷ VND) có thể bị ứ đọng nếu tiến độ triển khai chậm.', 6, 'Công ty có biên lợi nhuận gộp cao (59.6%) nhưng lợi nhuận giảm trong năm 2020. Nợ vay thấp, thanh khoản tốt. Điểm rủi ro là giao dịch với bên liên quan (cho vay không lãi suất) và dự án xây dựng dở dang lớn. Triển vọng trung bình, phụ thuộc vào tiến độ triển khai dự án và hiệu quả sản xuất thủy sản.'),
('VUG_2021_consolidated', 'VUG', 2021, 'consolidated', 'Công ty có giao dịch cho vay không lãi suất với bên liên quan Công ty TNHH Việt Úc - Ngọc Hiền và các giao dịch mua bán với công ty liên kết, có thể gây rủi ro xung đột lợi ích và ảnh hưởng đến tính minh bạch tài chính.', 'Nợ vay của công ty ở mức thấp với tổng nợ phải trả chiếm khoảng 7.5% tổng tài sản, áp lực nợ vay không cao và khả năng thanh toán đảm bảo.', 'Hàng tồn kho có dự phòng giảm giá đáng kể cho chi phí sản xuất kinh doanh dở dang, cho thấy rủi ro về hàng tồn kho chậm lưu chuyển hoặc lỗi thời, đặc biệt trong hoạt động nuôi trồng thủy sản.', 4, 'Công ty có tình hình tài chính lành mạnh với doanh thu và lợi nhuận tăng trưởng, biên lợi nhuận gộp cao, và dòng tiền hoạt động kinh doanh mạnh. Tuy nhiên, cần chú ý đến các giao dịch với bên liên quan không có lãi suất và quản lý hàng tồn kho. Công ty đang đầu tư mạnh vào mở rộng sản xuất và phát triển công nghệ, có triển vọng phát triển tích cực trong ngành thủy sản.'),
('VUG_2021_parent', 'VUG', 2021, 'parent', 'Công ty có giao dịch lớn với các công ty con và công ty liên kết, bao gồm bán hàng, mua hàng và cho vay không lãi suất. Điều này có thể cho thấy rủi ro về giao dịch liên kết nhằm chuyển giá hoặc chiếm dụng vốn, nhưng chưa có bằng chứng rõ ràng về bất thường.', 'Công ty không có nợ vay có lãi suất, nợ chủ yếu là phải trả ngắn hạn như phải trả người bán và lương nhân viên. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất kinh doanh dở dang, không có dự phòng giảm giá. Rủi ro tồn kho thấp do sản phẩm thủy sản có chu kỳ sản xuất ngắn.', 5, 'Công ty có tình hình tài chính khỏe mạnh với biên lợi nhuận gộp cao (~64%), tăng trưởng lợi nhuận, và không có nợ vay. Tuy nhiên, cần theo dõi giao dịch liên kết để đảm bảo minh bạch. Triển vọng đầu tư tích cực trong ngành thủy sản.'),
('VUG_2019_consolidated', 'VUG', 2019, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu bao gồm lương thưởng cho ban giám đốc, chia cổ tức cho cổ đông lớn và các khoản cho vay ngắn hạn. Các giao dịch này có vẻ bình thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay thấp. Công ty đã trả hết nợ vay ngắn hạn từ cổ đông vào cuối năm 2019. Nợ dài hạn khác chủ yếu là khoản ứng trước từ Trung tâm Phát triển Quỹ đất với thời hạn trả trước tháng 7/2021, có kế hoạch trả nợ rõ ràng.', 'Hàng tồn kho bao gồm nguyên vật liệu, thành phẩm và chi phí sản xuất kinh doanh dở dang. Dự phòng giảm giá hàng tồn kho tăng lên, cho thấy có một phần hàng tồn kho bị lỗi thời hoặc chậm lưu chuyển. Các dự án xây dựng dở dang có quy mô lớn, tập trung vào mở rộng sản xuất tôm giống và cá tra, cần theo dõi tiến độ và khả năng hoàn thành.', 3, 'Tập đoàn có tình hình tài chính lành mạnh với lợi nhuận tăng trưởng ổn định, tỷ suất lợi nhuận gộp cao. Dòng tiền từ hoạt động kinh doanh dương, khả năng thanh toán tốt. Các khoản đầu tư vào xây dựng cơ bản dở dang lớn cho thấy chiến lược mở rộng sản xuất. Tuy nhiên, cần lưu ý đến rủi ro hàng tồn kho và tiến độ các dự án đầu tư dài hạn.'),
('VUG_2020_parent', 'VUG', 2020, 'parent', 'Công ty có nhiều giao dịch với các công ty con, bao gồm cho vay không lãi suất, mua bán hàng hóa, và chia cổ tức. Điều này có thể tạo rủi ro về giao dịch không theo giá thị trường và ảnh hưởng đến lợi nhuận, nhưng không có bằng chứng gian lận rõ ràng.', 'Công ty không có nợ vay ngân hàng trong năm 2020, chỉ có các khoản phải trả ngắn hạn. Áp lực nợ thấp, khả năng thanh toán tốt.', 'Hàng tồn kho bao gồm nguyên vật liệu và chi phí sản xuất dở dang, không có dự phòng giảm giá. Các dự án xây dựng dở dang như hệ thống SAP đang triển khai, cần giám sát tiến độ và rủi ro chậm trễ.', 5, 'Trụ sở chính của Công ty Cổ phần Thủy sản Việt Úc có kết quả kinh doanh khả quan với lợi nhuận sau thuế 216.9 tỷ VNĐ năm 2020. Công ty không có nợ vay, tài sản chủ yếu là đầu tư vào công ty con và hàng tồn kho. Tuy nhiên, doanh thu giảm so với năm trước, và công ty phụ thuộc vào giao dịch với các bên liên quan. Triển vọng trung lập, cần theo dõi ngành thủy sản và quản trị công ty.'),
('VUG_2019_parent', 'VUG', 2019, 'parent', 'Công ty có giao dịch lớn với các công ty con, bao gồm cho vay không lãi suất và tín chấp, tạo rủi ro nếu công ty con gặp khó khăn thanh toán. Doanh thu bán hàng và mua hàng với công ty con chiếm tỷ trọng đáng kể, có thể liên quan đến giá chuyển nhượng nội bộ.', 'Công ty không có nợ vay ngân hàng cuối năm 2019, đã trả hết nợ ngắn hạn từ bên liên quan. Áp lực nợ vay thấp, không có tài sản thế chấp.', 'Hàng tồn kho tăng 36% so với năm trước, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng mạnh, phản ánh mở rộng sản xuất. Rủi ro tồn kho ở mức trung bình, không có dự phòng giảm giá.', 5, 'Công ty có kết quả kinh doanh tăng trưởng tốt với lợi nhuận sau thuế tăng 56%. Tài sản tăng mạnh chủ yếu do đầu tư vào công ty con và cho vay nội bộ. Công ty không có nợ vay ngân hàng, thanh khoản tốt. Tuy nhiên, phụ thuộc lớn vào giao dịch nội bộ với công ty con và cổ đông, cần theo dõi rủi ro quản trị.'),
('VUG_2018_parent', 'VUG', 2018, 'parent', 'Các giao dịch với các bên liên quan bao gồm mua bán hàng hóa, cho vay không lãi suất, và nhận cổ tức từ công ty con. Không có dấu hiệu giao dịch bất thường như mua bán chênh lệch lớn hay công ty sân sau.', 'Nợ vay ngắn hạn 24,5 tỷ VNĐ với lãi suất 5%/năm, áp lực nợ ở mức vừa phải. Công ty có khả năng thanh toán tốt với tài sản thế chấp không rõ ràng.', 'Hàng tồn kho giảm so với năm trước, không có dự phòng, rủi ro thấp. Các dự án xây dựng dở dang đang triển khai và chưa có dấu hiệu ứ đọng.', 5, 'Công ty có kết quả kinh doanh tốt với lợi nhuận cao năm 2018, nhưng phụ thuộc lớn vào doanh thu và cổ tức từ công ty con. Nợ vay ngắn hạn ở mức kiểm soát, nhưng cần theo dõi dòng tiền và hiệu quả đầu tư vào các dự án.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VUA_2025_consolidated', 'VUA', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thù lao, lương và phụ cấp cho ban lãnh đạo (HĐQT, Ban Tổng Giám đốc, Ban Kiểm soát) với tổng chi phí khoảng 2,49 tỷ đồng năm 2025. Trong đó, ông Nguyễn Quang Anh (Phó Tổng Giám đốc/Thành viên HĐQT) nhận khoản thù lao cao nhất 1,31 tỷ đồng; ông Luyện Quang Thắng (Chủ tịch HĐQT cũ) nhận 519 triệu đồng. Đây là thù lao quản lý thông thường, không phát hiện giao dịch mua bán, cho vay bất thường hay giao dịch với công ty con/công ty liên kết. Tuy nhiên, sự thay đổi nhân sự cấp cao lớn trong tháng 10-12/2025 (thay toàn bộ HĐQT, BKS, bổ nhiệm mới TGĐ) đặt ra câu hỏi về tính liên tục và ổn định quản trị.', 'Công ty phát sinh khoản vay ngắn hạn mới 25,17 tỷ đồng từ Ngân hàng TMCP Hàng Hải Việt Nam trong tháng 12/2025 (hạn mức tối đa 50 tỷ đồng, kỳ hạn 12 tháng). Chi phí lãi vay năm 2025 chỉ 67,6 triệu đồng, cho thấy áp lực nợ vay thấp. Tiền mặt cuối kỳ đạt 100,7 tỷ đồng, gấp 4 lần nợ vay ngắn hạn, đảm bảo khả năng thanh toán. Tài sản thế chấp là quyền đòi nợ từ hoạt động cho vay ký quỹ đã được đăng ký giao dịch bảo đảm. Không có nợ dài hạn.', 'Công ty là công ty chứng khoán, không có hàng tồn kho truyền thống hay dự án xây dựng. Danh mục tài sản tài chính sẵn sàng để bán (AFS) cuối năm 2025 trị giá 180,3 tỷ đồng, chuyển dịch hoàn toàn sang trái phiếu (bỏ toàn bộ cổ phiếu niêm yết và chưa niêm yết so với đầu năm). Ba trái phiếu chưa niêm yết lớn nhất chiếm phần lớn danh mục: Trái phiếu May-Diêm Sài Gòn (138,7 tỷ đồng, đáo hạn 2032), Trái phiếu ROX Energy (40 tỷ đồng, đáo hạn 2028), Trái phiếu Tập đoàn Hạ tầng Giáo dục (1,6 tỷ đồng, đáo hạn 2027). Rủi ro tập trung vào tính thanh khoản và khả năng thanh toán nợ của các tổ chức phát hành trái phiếu chưa niêm yết này.', 4, 'SBSI là công ty chứng khoán quy mô nhỏ với vốn điều lệ 339 tỷ đồng, đã lỗ lũy kế 74,4 tỷ đồng. Năm 2025 đánh dấu bước ngoặt khi công ty có lãi trở lại 3,3 tỷ đồng sau nhiều năm lỗ, nhờ giảm mạnh lỗ từ hoạt động FVTPL (giảm 96%) và cắt giảm chi phí hoạt động. Tuy nhiên, doanh thu từ các mảng dịch vụ truyền thống (môi giới -29%, tư vấn -82%, lưu ký -23%) đều sụt giảm mạnh, cho thấy năng lực cạnh tranh yếu. Hoạt động tự doanh là động lực tăng trưởng chính nhưng mang tính chu kỳ. Điểm tích cực: sau ngày lập BCTC (01/2026), công ty đã phát hành riêng lẻ thành công tăng vốn lên 2.000 tỷ đồng, giúp cải thiện đáng kể năng lực tài chính. Rủi ro lớn nhất là sự bất ổn trong ban lãnh đạo (thay đổi toàn diện HĐQT và TGĐ trong Q4/2025) và phụ thuộc quá lớn vào hoạt động tự doanh trong khi mảng dịch vụ cốt lõi suy giảm.'),
('VUA_2023_consolidated', 'VUA', 2023, 'consolidated', 'Giao dịch với bên liên quan bao gồm cho vay và thanh toán lãi suất cho các cá nhân nội bộ, số tiền không lớn và không có dấu hiệu bất thường, rủi ro thấp.', 'Công ty không có nợ vay, rủi ro thanh khoản thấp.', 'Tồn kho chủ yếu là công cụ, dụng cụ văn phòng có giá trị nhỏ, không có dự án xây dựng dở dang, rủi ro thấp.', 4, 'Công ty năm 2023 lỗ do doanh thu giảm mạnh do thị trường chứng khoán không thuận lợi. Tuy nhiên, cấu trúc tài sản ổn định, không nợ vay, tồn kho thấp. Giao dịch với bên liên quan bình thường. Công ty đối mặt với rủi ro thị trường nhưng nền tảng tài chính cơ bản còn vững chắc.'),
('VUA_2021_consolidated', 'VUA', 2021, 'consolidated', 'Không phát hiện giao dịch bất thường với bên liên quan. Các giao dịch chủ yếu liên quan đến thù lao ban lãnh đạo.', 'Nợ vay ngắn hạn 40 tỷ VND với lãi suất 9%/năm, tín chấp. Áp lực nợ vay ở mức trung bình, công ty có khả năng thanh toán từ dòng tiền kinh doanh.', 'Hàng tồn kho chủ yếu là công cụ dụng cụ giá trị nhỏ, không có dự án xây dựng dở dang, rủi ro thấp.', 3, 'Công ty chứng khoán Stanley Brothers có doanh thu tăng mạnh trong năm 2021 nhưng chi phí tự doanh cao dẫn đến lợi nhuận giảm. Tổng tài sản tăng chủ yếu từ tiền gửi và khoản cho vay. Nợ vay ngắn hạn tăng nhưng vẫn trong kiểm soát. Công ty có vị thế tài chính ổn định, tuy nhiên cần theo dõi rủi ro từ hoạt động tự doanh.'),
('VTZ_2024_consolidated', 'VTZ', 2024, 'consolidated', 'Công ty có giao dịch bán hàng lớn với Công ty Cổ phần Zlife Holdings (bên liên quan) với doanh thu 625.59 tỷ VND và phải thu 19.38 tỷ VND, chưa rõ điều kiện thanh toán có ưu đãi hay không, cần giám sát chặt chẽ.', 'Áp lực nợ vay cao với tổng nợ ngắn hạn 1.472 tỷ VND và nợ dài hạn 27.32 tỷ VND, chi phí lãi vay lớn 77 tỷ VND. Tài sản thế chấp bao gồm hàng tồn kho và bất động sản, nhưng đòn bẩy tài chính tăng mạnh sau phát hành cổ phiếu.', 'Tồn kho tăng từ 661 tỷ lên 824 tỷ VND, không trích lập dự phòng, có nguy cơ ứ đọng hoặc giảm giá nếu tiêu thụ chậm, đặc biệt với nguyên liệu và thành phẩm.', 5, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận sau thuế, nhưng lệ thuộc nhiều vào vốn vay và giao dịch bên liên quan. Khả năng sinh lời cải thiện, nhưng cần quản lý rủi ro nợ và tồn kho hiệu quả. Triển vọng trung bình với tiềm năng mở rộng kinh doanh.'),
('VTZ_2025_consolidated', 'VTZ', 2025, 'consolidated', 'Doanh nghiệp có giao dịch bán hàng đáng kể với Công ty Cổ phần Zlife Holdings, một bên liên quan qua cổ đông lớn Nguyễn Phúc Lợi, tạo rủi ro tập trung khách hàng và phụ thuộc vào giao dịch nội bộ.', 'Nợ vay ngắn hạn và dài hạn cao với nhiều ngân hàng, dẫn đến đòn bẩy tài chính lớn và chi phí lãi vay nặng, áp lực thanh toán ngắn hạn cao, tài sản thế chấp chủ yếu là hàng tồn kho và bất động sản.', 'Hàng tồn kho lớn, bao gồm nguyên liệu, thành phẩm và hàng gửi bán, không có dự phòng giảm giá, tiềm ẩn rủi ro ứ đọng và lỗi thời.', 7, 'Doanh nghiệp tăng trưởng doanh thu nhưng lợi nhuận giảm nhẹ, nợ vay cao và giao dịch bên liên quan đáng lo ngại. Cần cải thiện quản lý tồn kho và giảm phụ thuộc vào nợ vay để đảm bảo sức khỏe tài chính.'),
('VTZ_2025_parent', 'VTZ', 2025, 'parent', 'Doanh thu bán hàng với bên liên quan Zlife Holdings chiếm tỷ trọng lớn (khoảng 15.7% doanh thu thuần). Các giao dịch mua hàng và góp vốn với công ty con diễn ra thường xuyên. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất, nhưng cần theo dõi tỷ trọng giao dịch với bên liên quan để đảm bảo tính minh bạch.', 'Áp lực nợ vay cao với nợ ngắn hạn chiếm phần lớn (trên 2.199 tỷ VND). Công ty vay từ đa dạng ngân hàng và công ty cho thuê tài chính. Phần lớn các khoản vay ngắn hạn có tài sản đảm bảo (hàng tồn kho, tiền gửi, bất động sản, quyền đòi nợ). Chi phí lãi vay năm nay là 125,8 tỷ VND, tăng mạnh so với năm trước. Cần theo dõi khả năng trả nợ và biến động lãi suất.', 'Hàng tồn kho tăng mạnh so với đầu năm (tăng hơn 202 tỷ VND), trong đó hàng gửi bán chiếm tỷ trọng lớn (293,7 tỷ VND). Hàng tồn kho luân chuyển cao, rủi ro ứ đọng và mất giá cần được kiểm soát chặt chẽ.', 5, 'Công ty tăng trưởng doanh thu mạnh (tăng 38.7%) nhưng lợi nhuận sau thuế giảm nhẹ. Nợ vay tăng cao để tài trợ hoạt động kinh doanh và đầu tư, tạo áp lực tài chính lớn. Hàng tồn kho tăng, cần quản lý hiệu quả. Sức khỏe tài chính cơ bản ổn định nhưng đòn bẩy tài chính cao, tiềm ẩn rủi ro nếu kinh doanh gặp khó khăn.'),
('VTZ_2024_parent', 'VTZ', 2024, 'parent', 'Công ty có giao dịch mua bán lớn với công ty con (Cơ khí Việt Thành) và đặc biệt là doanh thu bán hàng lớn với Công ty Cổ phần Zlife Holdings (liên quan đến cổ đông lớn). Các giao dịch này được Hội đồng Quản trị phê duyệt, tuy nhiên việc tập trung doanh thu vào một bên liên quan có thể tạo ra rủi ro về tính độc lập và công bằng trong giao dịch. Không có thông tin về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay và nợ thuê tài chính chiếm tỷ trọng lớn trong tổng nguồn vốn (tổng nợ phải trả cuối năm là 1.593.506.229.145 đồng so với tổng tài sản 2.410.434.989.551 đồng). Công ty vay từ nhiều ngân hàng và tổ chức tín dụng, áp lực trả nợ ngắn hạn cao (1.471.277.681.914 đồng nợ ngắn hạn). Tài sản đảm bảo chủ yếu là hàng tồn kho luân chuyển, bất động sản và tiền gửi có kỳ hạn, điều này làm giảm tính thanh khoản của tài sản. Công ty đã phát hành cổ phiếu riêng lẻ để tăng vốn chủ sở hữu nhằm giảm bớt áp lực nợ.', 'Hàng tồn kho tăng mạnh từ 657.366.319.137 đồng lên 818.646.404.033 đồng, trong đó thành phẩm và hàng hóa chiếm tỷ trọng lớn. Nguyên liệu, vật liệu cũng tăng. Điều này có thể phản ánh hoạt động kinh doanh mở rộng, nhưng cũng tiềm ẩn rủi ro ứ đọng, lỗi thời hoặc giảm giá. Công ty không trích lập dự phòng giảm giá hàng tồn kho trong năm.', 6, 'Công ty có sự tăng trưởng mạnh về doanh thu và lợi nhuận sau thuế trong năm 2024. Tuy nhiên, công ty phụ thuộc nhiều vào vốn vay, áp lực nợ ngắn hạn lớn. Hàng tồn kho tăng nhanh cần được giám sát. Công ty đã thực hiện tăng vốn chủ sở hữu qua phát hành cổ phiếu riêng lẻ và cổ tức bằng cổ phiếu để cải thiện cơ cấu vốn. Giao dịch với các bên liên quan là một điểm cần lưu ý. Khả năng thanh toán và quản lý dòng tiền cần được theo dõi chặt chẽ.'),
('VTZ_2023_consolidated', 'VTZ', 2023, 'consolidated', 'Công ty có giao dịch với bên liên quan là công ty con và Tổng Giám đốc. Năm nay, giao dịch bao gồm doanh thu cung cấp dịch vụ và mua tài sản với giá trị hợp lý. Năm trước có khoản ứng trước lớn 113 tỷ VND cho Tổng Giám đốc đã được hoàn trả. Rủi ro thấp nhưng cần theo dõi giao dịch với bên liên quan.', 'Công ty có nợ vay lớn, chủ yếu là ngắn hạn với lãi suất biến động. Chi phí lãi vay cao (61.6 tỷ VND năm 2023) và dòng tiền hoạt động kinh doanh âm (-390.8 tỷ VND). Áp lực trả nợ lớn, phụ thuộc vào việc tái cấp vốn và tài sản thế chấp.', 'Hàng tồn kho tăng từ 496 tỷ VND lên 657 tỷ VND, bao gồm nguyên liệu, thành phẩm và chi phí dở dang. Không có dự phòng giảm giá, cho thấy rủi ro tồn kho dở dang hoặc hàng hóa có thể bị ứ đọng nếu nhu cầu giảm.', 5, 'Công ty đạt lợi nhuận tăng trưởng nhẹ (23.4 tỷ VND năm 2023 so với 25.0 tỷ VND năm trước), nhưng dòng tiền kinh doanh âm do tăng vốn lưu động. Nợ vay cao, chủ yếu ngắn hạn, tạo áp lực tài chính. Tài sản thế chấp đầy đủ nhưng thanh khoản cần được cải thiện. Triển vọng trung bình, phụ thuộc vào khả năng quản lý nợ và tồn kho.'),
('VTZ_2022_consolidated', 'VTZ', 2022, 'consolidated', 'Công ty có giao dịch với bên liên quan là Tổng Giám đốc với khoản trả trước lớn (hơn 80 tỷ VNĐ cho đất và hơn 1 tỷ VNĐ tạm ứng), cần theo dõi khả năng thu hồi và tính minh bạch.', 'Công ty có nợ vay ngắn hạn lớn (hơn 555 tỷ VNĐ) và nợ dài hạn, chủ yếu được đảm bảo bằng hàng tồn kho, bất động sản và tài sản cố định, áp lực trả nợ và chi phí lãi vay cao.', 'Hàng tồn kho bao gồm nguyên liệu, thành phẩm và chi phí sản xuất dở dang với giá trị lớn, không có dự phòng giảm giá, rủi ro tồn kho trung bình do biến động giá nguyên liệu.', 6, 'Công ty có tăng trưởng doanh thu mạnh (63%) nhưng lợi nhuận gộp biên thấp (6.4%), nợ vay cao và giao dịch bên liên quan đáng chú ý. Tình hình tài chính ổn định nhưng cần cải thiện quản trị rủi ro và giảm đòn bẩy để bền vững.'),
('VTZ_2022_parent', 'VTZ', 2022, 'parent', 'Công ty có giao dịch đáng chú ý với Tổng Giám đốc Phan Văn Quân: ứng trước tiền mua đất 113 tỷ VNĐ để xây dựng kho và showroom, Công ty đang tiến hành thủ tục pháp lý chuyển đổi sang tên. Công ty con (Đầu tư và XNK Cơ khí Việt Thành) có doanh thu dịch vụ và phải trả ngược lại Công ty mẹ. Công ty trả trước mua đất qua cổ đông Nguyễn Văn Út, bà Lý Thị Ngọc Mai và ông Đồng Bội Ngọc (năm trước), tổng giá trị lớn. Các giao dịch này cần được giám sát chặt chẽ.', 'Tổng nợ vay và thuê tài chính là 588.7 tỷ VNĐ (nợ ngắn hạn 555 tỷ, nợ dài hạn 33.7 tỷ). Tỷ lệ nợ vay/tổng tài sản đạt ~47%. Chi phí lãi vay năm 2022 là 41.7 tỷ VNĐ, chiếm tỷ trọng đáng kể trong lợi nhuận thuần từ kinh doanh (32.3 tỷ). Nợ ngắn hạn chiếm tỷ trọng áp đảo so với nợ dài hạn, gây áp lực trả nợ lớn. Tài sản thế chấp bao gồm hàng hóa, bất động sản, đất đai, giấy tờ có giá, tiết kiệm cá nhân của ban lãnh đạo. Công ty có vay nước ngoài không lãi suất từ VIH CAPITAL nhưng chỉ 10 tỷ VNĐ.', 'Hàng tồn kho trị giá 495.9 tỷ VNĐ, tăng 29% so với năm trước (383.8 tỷ). Không có dự phòng giảm giá hàng tồn kho được trích lập. Hàng tồn kho chủ yếu là nguyên vật liệu (267.5 tỷ) và thành phẩm (226.3 tỷ), không có hàng mua đang đi đường tại ngày cuối kỳ. Có chi phí sản xuất kinh doanh dở dang 2.2 tỷ. Công ty có chi phí xây dựng cơ bản dở dang 1 tỷ mua sắm tài sản cố định, chưa có dự án bất động sản dở dang lớn.', 6, 'Nhựa Việt Thành đạt doanh thu thuần 1,785.9 tỷ VNĐ tăng 64% so với năm trước, biên lợi nhuận gộp 6.4%. Công ty có tỷ lệ nợ vay cao với tổng nợ vay/thuê tài chính 588.7 tỷ VNĐ, chi phí lãi vay 41.7 tỷ chiếm tỷ trọng lớn so với lợi nhuận thuần từ kinh doanh. Giao dịch đáng chú ý là ứng trước 113 tỷ VNĐ cho Tổng Giám đốc mua đất, cùng với các khoản trả trước qua cổ đông. Công ty con mới được thành lập với vốn góp 4.7 tỷ VNĐ. Hàng tồn kho tăng mạnh mà không trích lập dự phòng. Điểm rủi ro quản trị ở mức trung bình cao do các giao dịch liên quan đến ban lãnh đạo và đòn bẩy tài chính lớn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTX_2023_consolidated', 'VTX', 2023, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan trong cùng tập đoàn (Sotrans Group). Các giao dịch chủ yếu là vay mượn, thuê tài sản và dịch vụ vận chuyển, không có lãi suất hoặc lãi suất không được tiết lộ rõ ràng. Công ty mẹ (Kho vận Miền Nam) cung cấp bảo lãnh ngân hàng lớn cho các khoản vay. Rủi ro tập trung vào việc phụ thuộc vào tập đoàn và khả năng kiểm soát giá chuyển nhượng.', 'Áp lực nợ vay lớn, tổng nợ vay và nợ thuê tài chính giảm mạnh từ 135.9 tỷ xuống 42.7 tỷ VND trong năm. Tuy nhiên, Công ty vẫn có khoản nợ ngắn hạn đáng kể (26.2 tỷ) và nợ dài hạn (16.5 tỷ) với các ngân hàng và công ty liên quan. Công ty có lỗ lũy kế lớn (-40.6 tỷ) và lỗ hoạt động kinh doanh (-118.7 tỷ) trong năm, tạo áp lực trả nợ. Tài sản thế chấp bao gồm phương tiện vận tải và bảo lãnh của công ty mẹ.', 'Hàng tồn kho giảm mạnh từ 101.6 tỷ xuống 46.9 tỷ VND, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang. Dự phòng giảm giá hàng tồn kho đã được hoàn nhập toàn bộ. Rủi ro tồn kho thấp nhưng cần theo dõi dự án xây dựng dở dang (7.1 tỷ VND).', 6, 'Công ty gặp khó khăn tài chính nghiêm trọng trong năm 2023 với lỗ ròng 78 tỷ VND, doanh thu giảm 57% so với năm trước. Biên lợi nhuận gộp âm (-52.4%) cho thấy hoạt động kinh doanh chính không hiệu quả. Công ty bù đắp một phần bằng thu nhập từ thanh lý tài sản cố định (78.4 tỷ). Rủi ro quản trị ở mức trung bình cao do nhiều giao dịch với bên liên quan và lỗ lũy kế lớn. Khả năng hoạt động liên tục phụ thuộc vào hỗ trợ từ công ty mẹ và việc tái cơ cấu nợ. Triển vọng đầu tư tiêu cực trong ngắn hạn.'),
('VTX_2025_consolidated', 'VTX', 2025, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan trong Tập đoàn ITL, bao gồm mua bán dịch vụ, cho thuê tài sản và vay nợ. Các khoản phải thu và phải trả với bên liên quan không có lãi suất và không cần bảo đảm, nhưng mức độ giao dịch đáng kể có thể ảnh hưởng đến tính độc lập của công ty.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 62.9 tỷ VND, với lỗ lũy kế 180.7 tỷ VND. Công ty phụ thuộc vào sự hỗ trợ tài chính từ công ty mẹ để duy trì hoạt động. Lãi suất vay từ 6% đến 7.9% mỗi năm, áp lực nợ vay cao.', 'Hàng tồn kho có dự phòng giảm giá 706 triệu VND cho nhiên liệu vật liệu, nhưng tổng giá trị tồn kho giảm so với năm trước. Không có dự án bất động sản, chỉ có chi phí xây dựng cơ bản dở dang.', 6, 'Công ty hoạt động trong ngành vận tải đa phương thức, liên tục lỗ trong hai năm qua. Tình hình tài chính khó khăn, với nợ vay cao và vốn chủ sở hữu bị ăn mòn. Triển vọng phụ thuộc vào sự hỗ trợ từ công ty mẹ và khả năng cải thiện lợi nhuận. Rủi ro đầu tư cao.'),
('VTX_2024_consolidated', 'VTX', 2024, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan trong tập đoàn, bao gồm cho vay, thuê tài sản và dịch vụ. Các khoản vay từ bên liên quan có lãi suất thị trường (6.38%/năm), nhưng số dư phải thu và phải trả lớn, có thể ảnh hưởng đến thanh khoản. Không có dấu hiệu giao dịch bất thường nghiêm trọng, nhưng cần giám sát chặt chẽ.', 'Công ty có nợ phải trả tổng cộng 136,449,571,126 VND, trong đó nợ ngắn hạn là 109,912,460,603 VND, vượt quá tài sản ngắn hạn. Áp lực nợ vay cao, đặc biệt với các khoản vay ngân hàng và thuê tài chính. Tài sản thế chấp bao gồm phương tiện vận tải, máy móc và bảo lãnh từ công ty mẹ, nhưng rủi ro thanh toán vẫn cao do lỗ lũy kế.', 'Hàng tồn kho giảm mạnh từ 46,896,927,828 VND xuống 15,428,014,858 VND, có thể do hoàn thành dự án hoặc giảm hoạt động. Dự án xây dựng dở dang trị giá 9,201,808,247 VND đang triển khai, nhưng không có thông tin về tiến độ, tiềm ẩn rủi ro chậm trễ hoặc ứ đọng.', 7, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế 145,337,335,266 VND và dòng tiền âm từ hoạt động kinh doanh. Tuy nhiên, có sự hỗ trợ cam kết từ công ty mẹ và kế hoạch kinh doanh mới, nên triển vọng phụ thuộc vào khả năng hồi phục hoạt động, quản lý nợ và giảm chi phí.'),
('VTX_2022_consolidated', 'VTX', 2022, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm vay vốn không lãi suất từ công ty mẹ, thuê văn phòng và thanh lý tài sản. Các giao dịch này có thể tạo ra rủi ro về tính công bằng và minh bạch, đặc biệt là khoản vay lớn không lãi suất có thể ảnh hưởng đến lợi nhuận và dòng tiền.', 'Áp lực nợ vay tương đối cao với tổng nợ khoảng 135,9 tỷ VNĐ, bao gồm nợ ngắn hạn và dài hạn từ ngân hàng và thuê tài chính. Nợ ngắn hạn chiếm tỷ trọng lớn, đòi hỏi khả năng thanh toán nhanh. Tài sản thế chấp bao gồm phương tiện vận tải và thư bảo lãnh từ công ty mẹ, nhưng mức độ đòn bẩy tài chính có thể gây rủi ro nếu hoạt động kinh doanh suy giảm.', 'Hàng tồn kho bao gồm chi phí sản xuất dở dang lớn (81,6 tỷ VNĐ), có thể ứ đọng nếu dự án chậm tiến độ. Dự phòng giảm giá hàng tồn kho được hoàn nhập một phần, cho thấy cải thiện, nhưng rủi ro vẫn tồn tại do biến động thị trường.', 6, 'Sức khỏe tài chính của công ty đang đối mặt với thách thức: lợi nhuận giảm mạnh, nợ vay tăng, và dòng tiền từ hoạt động kinh doanh âm. Tuy nhiên, công ty có tài sản cố định lớn và dòng tiền từ hoạt động tài chính dương do vay mới. Triển vọng phụ thuộc vào khả năng quản lý nợ và tối ưu hóa hoạt động vận tải trong môi trường kinh tế khó khăn.'),
('VTX_2017_consolidated', 'VTX', 2017, 'consolidated', 'Doanh nghiệp có giao dịch lớn với công ty mẹ Kho vận Miền Nam, bao gồm cho vay, thu hồi nợ, cung cấp dịch vụ, mua nhiên liệu, cho thuê văn phòng. Các giao dịch này có thể ảnh hưởng đến tính độc lập của doanh nghiệp, tuy nhiên có tính lãi suất và được ghi nhận đầy đủ.', 'Nợ vay ngắn hạn tăng mạnh từ 15.7 tỷ lên 33.0 tỷ, áp lực trả nợ ngắn hạn cao. Nợ được đảm bảo bằng quyền sử dụng đất và phương tiện vận tải.', 'Hàng tồn kho tăng từ 9.6 tỷ lên 20.3 tỷ, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng mạnh từ 954 triệu lên 10.0 tỷ, có thể liên quan đến dự án vận chuyển lớn, cần theo dõi khả năng thu hồi.', 5, 'Doanh nghiệp có doanh thu giảm so với năm trước, lợi nhuận sau thuế giảm 63.9%. Hàng tồn kho tăng mạnh do chi phí dở dang. Nợ ngắn hạn tăng, nhưng có tài sản đảm bảo. Giao dịch bên liên quan đáng lưu ý với công ty mẹ.'),
('VTX_2021_consolidated', 'VTX', 2021, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt vay mượn từ công ty mẹ, có thể tiềm ẩn rủi ro giao dịch không công bằng.', 'Nợ vay tăng mạnh, đặc biệt nợ thuê tài chính, với tài sản thế chấp là quyền sử dụng đất và phương tiện vận tải. Áp lực trả nợ ngắn hạn lớn.', 'Hàng tồn kho tăng đột biến, chủ yếu là chi phí sản xuất kinh doanh dở dang, có nguy cơ ứ đọng và cần trích lập dự phòng.', 7, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận, nhưng nợ vay và hàng tồn kho tăng cao, cần theo dõi. Khả năng thanh toán nợ phụ thuộc vào hoạt động kinh doanh.'),
('VTX_2016_consolidated', 'VTX', 2016, 'consolidated', 'Có giao dịch vay lớn với công ty mẹ, có thể ảnh hưởng đến thanh khoản và tiềm ẩn rủi ro về giao dịch bên liên quan.', 'Nợ vay ngắn hạn ở mức vừa phải, công ty có đủ tiền và tương đương tiền để trả nợ. Tuy nhiên, cần theo dõi lãi suất và đáo hạn.', 'Hàng tồn kho có phần bị ứ đọng và mất phẩm chất, cần quản lý chặt chẽ.', 5, 'Công ty có kết quả kinh doanh tăng trưởng mạnh trong năm 2016, tuy nhiên doanh thu giảm. Tình hình tài chính cải thiện với tỷ suất lợi nhuận tăng, nhưng cần lưu ý doanh thu giảm và giao dịch bên liên quan.'),
('VTX_2019_consolidated', 'VTX', 2019, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm đầu tư vào trái phiếu của Công ty Cổ phần chứng khoán IB (bên liên quan) với giá trị lớn (hơn 20.9 tỷ VND) và cho cá nhân là Chủ tịch HĐQT, Phó Tổng Giám đốc vay tạm ứng không lãi suất với tổng cộng 3.68 tỷ VND. Các giao dịch này có thể tiềm ẩn rủi ro về xung đột lợi ích và quản trị.', 'Nợ vay ngắn hạn chỉ có 3.77 tỷ VND, đáo hạn vào ngày 19/02/2020 (ngay sau thời điểm lập BCTC). Áp lực nợ vay thấp, nhưng tài sản thế chấp là quyền sử dụng đất (giá trị còn lại 7.55 tỷ VND) là tài sản quan trọng của doanh nghiệp.', 'Hàng tồn kho giảm từ 23.08 tỷ VND xuống 16.74 tỷ VND, trong đó chi phí sản xuất kinh doanh dở dang giảm mạnh từ 12.63 tỷ VND xuống 6.16 tỷ VND, cho thấy tiến độ hoàn thành các dự án hoặc cắt giảm quy mô. Không có thông tin về dự phòng giảm giá hàng tồn kho.', 5, 'Doanh thu thuần giảm 20.8% so với năm trước, lợi nhuận sau thuế giảm 27.2%. Hàng tồn kho giảm mạnh, nợ vay thấp. Tuy nhiên, doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt là đầu tư vào trái phiếu của công ty liên quan và cho vay cá nhân ban lãnh đạo. Dòng tiền từ hoạt động kinh doanh giảm mạnh. Sức khỏe tài cơ bản ổn định nhưng tăng trưởng chậm và tiềm ẩn rủi ro quản trị.'),
('VTV_2025_consolidated', 'VTV', 2025, 'consolidated', 'Không có thông tin về giao dịch bên liên quan trong báo cáo tài chính được cung cấp.', 'Không có thông tin chi tiết về nợ vay trong báo cáo tài chính được cung cấp.', 'Không có thông tin về hàng tồn kho hoặc dự án trong báo cáo tài chính được cung cấp.', 3, 'Doanh nghiệp ghi nhận lợi nhuận sau thuế năm 2025 là 638,776,151 VND, tăng so với năm trước do doanh thu than cám tăng và doanh thu tài chính từ lãi chậm thanh toán 5.09 tỷ đồng. Kiểm toán đưa ra ý kiến chấp nhận toàn phần. Không có thông tin chi tiết về giao dịch bên liên quan, nợ vay và hàng tồn kho trong báo cáo được cung cấp, nên đánh giá rủi ro quản trị ở mức thấp do công ty tuân thủ quy định công bố thông tin.'),
('VTX_2015_consolidated', 'VTX', 2015, 'consolidated', 'Công ty có giao dịch với công ty liên doanh BNX - Vietranstimex (đầu tư 816 triệu VND, phải trả 816 triệu VND) và cổ đông lớn SCIC (58,60% vốn). Sau ngày kết thúc năm tài chính, SCIC đã thoái vốn toàn bộ 12.290.640 cổ phiếu, chuyển giao quyền kiểm soát cho nhiều nhà đầu tư cá nhân và tổ chức khác. Thay đổi sở hữu lớn này có thể ảnh hưởng đến chiến lược kinh doanh và quản trị công ty. Tuy nhiên, trong năm 2015, các giao dịch với bên liên quan không có dấu hiệu bất thường đáng kể.', 'Tổng nợ vay và nợ thuê tài chính tại 31/12/2015 là 35.603.944.391 đồng, giảm mạnh so với 98.663.437.537 đồng đầu năm, cho thấy Công ty đã chủ động giảm đòn bẩy tài chính. Nợ ngắn hạn 28.075.544.391 đồng chiếm tỷ trọng lớn. Công ty đã dùng tài sản cố định hữu hình (giá trị còn lại 84,4 tỷ đồng) và quyền sử dụng đất (10,2 tỷ đồng) để thế chấp cho các khoản vay. Tuy nhiên, với dòng tiền từ hoạt động kinh doanh thuần đạt 143,1 tỷ đồng trong năm 2015 và tiền mặt cuối năm đạt 69,3 tỷ đồng, khả năng thanh toán nợ ngắn hạn của Công ty ở mức an toàn.', 'Hàng tồn kho giảm từ 39,3 tỷ đồng xuống 17,2 tỷ đồng (giảm 56%), trong đó chi phí sản xuất kinh doanh dở dang giảm mạnh từ 29,4 tỷ xuống 5,1 tỷ đồng, cho thấy Công ty đã đẩy nhanh tiến độ hoàn thành sản phẩm. Dự phòng giảm giá hàng tồn kho tăng từ 6 triệu lên 512 triệu đồng, phản ánh một phần hàng hóa bị giảm giá trị. Chi phí xây dựng cơ bản dở dang chỉ còn 310 triệu đồng, các dự án đã cơ bản hoàn thành. Nhìn chung, rủi ro tồn kho ở mức thấp.', 4, 'Năm 2015, Công ty Cổ phần Vận tải Đa phương thức đạt kết quả kinh doanh tích cực: doanh thu thuần tăng 18,7% lên 580,4 tỷ đồng, lợi nhuận sau thuế đạt 18,3 tỷ đồng (gấp 2,7 lần năm 2014). Dòng tiền từ hoạt động kinh doanh thuần đạt 143,1 tỷ đồng, cho thấy hiệu quả hoạt động cải thiện mạnh. Công ty đã giảm nợ vay từ 98,7 tỷ xuống 35,6 tỷ đồng, tăng tiền mặt từ 18 tỷ lên 69,3 tỷ đồng, cải thiện đáng kể cơ cấu tài chính. EPS tăng từ 328 đồng/cổ phiếu lên 872 đồng/cổ phiếu. Tuy nhiên, sự kiện SCIC thoái vốn toàn bộ sau ngày lập báo cáo (tháng 1/2016) tạo ra thay đổi lớn về cơ cấu cổ đông, cần theo dõi tác động đến chiến lược và quản trị công ty. Công ty cũng thực hiện khấu hao nhanh một số tài sản cố định làm tăng chi phí khấu hao 25,3 tỷ đồng so với năm trước.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VTV_2024_consolidated', 'VTV', 2024, 'consolidated', 'Công ty có doanh thu bán hàng chủ yếu đến từ các bên liên quan trong cùng Tổng công ty VICEM, chiếm tỷ trọng cao (khoảng 80% doanh thu), cho thấy sự phụ thuộc đáng kể vào giao dịch nội bộ, có thể dẫn đến rủi ro về giá cả và tính công bằng trong giao dịch.', 'Nợ ngắn hạn lớn (342,98 tỷ VND) trong khi công ty lỗ ròng năm 2024, tạo áp lực thanh toán. Tài sản thế chấp chủ yếu là bất động sản và quyền đòi nợ, nhưng dòng tiền từ hoạt động kinh doanh giảm, có thể ảnh hưởng đến khả năng trả nợ.', 'Hàng tồn kho không có dự phòng giảm giá, giá trị tăng so với đầu năm, nhưng không có thông tin về khả năng tiêu thụ. Cần theo dõi rủi ro ứ đọng hàng tồn kho.', 7, 'Tình hình tài chính của công ty năm 2024 gặp khó khăn do lỗ ròng 7.5 tỷ VND, doanh thu giảm mạnh so với năm trước. Phụ thuộc lớn vào giao dịch với các công ty xi măng trong cùng Tổng công ty VICEM. Nợ ngắn hạn cao và dòng tiền từ hoạt động kinh doanh giảm. Triển vọng đầu tư thận trọng, cần cải thiện hiệu quả kinh doanh và quản lý nợ.'),
('VTV_2023_consolidated', 'VTV', 2023, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các công ty con của công ty mẹ VICEM, tập trung vào mua bán hàng hóa và dịch vụ. Các giao dịch này được thực hiện theo giá thị trường. Có khoản vay từ công ty mẹ không có tài sản đảm bảo, nhưng không có dấu hiệu giao dịch bất thường đáng kể.', 'Công ty có áp lực nợ vay ngắn hạn lớn (498 tỷ VNĐ), chi phí lãi vay tăng cao (47 tỷ VNĐ). Tuy nhiên, dòng tiền từ hoạt động kinh doanh mạnh (220 tỷ VNĐ) giúp giảm rủi ro thanh khoản. Các khoản vay ngân hàng được đảm bảo bằng tài sản.', 'Hàng tồn kho giảm mạnh từ 378 tỷ xuống 16 tỷ VNĐ, chủ yếu do giảm hàng hóa. Không có dự án dở dang, rủi ro tồn kho thấp.', 6, 'Công ty có doanh thu giảm so với năm trước nhưng vẫn duy trì lợi nhuận. Dòng tiền hoạt động kinh doanh mạnh, cải thiện đáng kể. Nợ vay ngắn hạn lớn nhưng được kiểm soát bởi dòng tiền. Hàng tồn kho giảm mạnh, giảm rủi ro. Sự phụ thuộc vào giao dịch với công ty con của công ty mẹ có thể tạo rủi ro tập trung.'),
('VTV_2022_consolidated', 'VTV', 2022, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan (các công ty con, công ty mẹ trong hệ thống VICEM). Doanh thu bán hàng cho bên liên quan chiếm tỷ trọng lớn, giao dịch mua hàng cũng phát sinh với một số công ty liên quan. Tuy nhiên, không phát hiện giao dịch bất thường rõ ràng (cho vay không lãi suất, mua bán chênh lệch lớn). Rủi ro tập trung ở mức độ phụ thuộc vào hệ sinh thái VICEM.', 'Công ty có nợ vay ngắn hạn lớn (679.5 tỷ VNĐ) với nhiều ngân hàng, chủ yếu phục vụ vốn lưu động kinh doanh than. Nợ tập trung ngắn hạn, áp lực trả nợ cao. Tài sản đảm bảo chủ yếu là hàng hóa, quyền đòi nợ từ hợp đồng thương mại. Cần theo dõi khả năng xoay vòng vốn.', 'Hàng tồn kho tăng mạnh từ 198 tỷ lên 379 tỷ VNĐ, chủ yếu là hàng hóa (than đá). Hàng tồn kho không trích lập dự phòng. Rủi ro tồn kho than có thể biến động theo giá thị trường và nhu cầu tiêu thụ. Không có tồn kho bất động sản dở dang.', 6, 'Công ty hoạt động trong lĩnh vực kinh doanh than và bất động sản, tăng trưởng doanh thu và lợi nhuận mạnh năm 2022 (doanh thu tăng 133%, lợi nhuận sau thuế tăng 37.69%). Tuy nhiên, công ty phụ thuộc lớn vào hệ sinh thái VICEM (công ty mẹ và các công ty con). Nợ vay ngắn hạn tăng mạnh, tiềm ẩn rủi ro thanh khoản. Hàng tồn kho lớn, cần giám sát biến động giá. Sự thay đổi nhân sự chủ chốt (Chủ tịch HĐQT bị bắt) có thể ảnh hưởng đến quản trị. Triển vọng phụ thuộc vào ngành xi măng và thị trường than.'),
('VTV_2020_consolidated', 'VTV', 2020, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan là công ty con và công ty mẹ trong lĩnh vực xi măng. Các giao dịch chủ yếu là mua bán hàng hóa, dịch vụ và tài chính, không có dấu hiệu bất thường nhưng cần giám sát để đảm bảo tính công bằng.', 'Nợ vay chủ yếu là ngắn hạn từ các ngân hàng với tài sản thế chấp. Áp lực nợ vay cao do dư nợ lớn, nhưng công ty có dòng tiền từ hoạt động kinh doanh và tài sản đảm bảo. Cần quản lý thanh khoản chặt chẽ.', 'Hàng tồn kho bao gồm bất động sản thành phẩm và hàng hóa. Dự án bất động sản có thể chịu rủi ro thị trường do ảnh hưởng của dịch COVID-19 và chờ quyết toán. Hàng hóa có rủi ro giảm giá.', 5, 'Lợi nhuận năm 2020 giảm mạnh so với 2019 do thuế bổ sung theo Nghị định 132/2020 và giảm doanh thu. Tuy nhiên, công ty vẫn có lợi nhuận và dòng tiền từ kinh doanh. Nợ vay cần được tái cơ cấu. Triển vọng phụ thuộc vào thị trường bất động sản và ngành xi măng.'),
('VTV_2021_consolidated', 'VTV', 2021, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan thuộc Tổng công ty Xi măng Việt Nam (VICEM), bao gồm bán hàng và mua dịch vụ. Doanh thu từ các công ty con chiếm tỷ trọng cao, tạo sự phụ thuộc và rủi ro về giá chuyển nhượng. Tuy nhiên, giao dịch diễn ra trong nhóm và có hợp đồng rõ ràng.', 'Công ty có nợ vay ngắn hạn lớn với tổng số 250 tỷ VNĐ, chủ yếu từ các ngân hàng thương mại và công ty mẹ. Nợ được đảm bảo bằng tài sản như hàng tồn kho và bất động sản, nhưng áp lực thanh toán ngắn hạn cao. Chi phí lãi vay năm 2021 là 15.2 tỷ VNĐ, giảm so với năm trước do giảm dư nợ.', 'Hàng tồn kho bao gồm nguyên liệu, thành phẩm bất động sản và hàng hóa. Không có dự phòng giảm giá, nhưng bất động sản đầu tư thuộc Dự án Comatce Tower có thể bị ảnh hưởng bởi thị trường cho thuê văn phòng khó khăn do dịch COVID-19.', 5, 'Công ty đạt lợi nhuận tăng mạnh năm 2021 nhờ tăng sản lượng than và doanh thu bất động sản. Tuy nhiên, công ty có rủi ro về giao dịch bên liên quan và nợ ngắn hạn. Quản trị ở mức trung bình với thành viên Hội đồng quản trị độc lập. Triển vọng phụ thuộc vào thị trường than và bất động sản.'),
('VTV_2017_consolidated', 'VTV', 2017, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, chủ yếu là mua bán hàng hóa và dịch vụ với công ty mẹ và các công ty con trong tổng công ty. Giao dịch với tổng giá trị lớn nhưng dựa trên hoạt động kinh doanh bình thường, chưa phát hiện dấu hiệu bất thường hoặc chuyển giá đáng kể.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao, lãi suất thả nổi theo từng giấy nhận nợ, tạo áp lực về chi phí lãi vay. Công ty có thế chấp tài sản cố định cho một số khoản vay, nhưng khả năng thanh toán phụ thuộc vào dòng tiền kinh doanh.', 'Hàng tồn kho chủ yếu là than cám, mặt hàng chịu biến động giá. Trong kỳ, hàng tồn kho giảm mạnh do hoạt động bán hàng, chưa có dấu hiệu tồn kho ứ đọng. Dự án tòa nhà Comatce đang trong quá trình xây dựng, có rủi ro chậm tiến độ.', 5, 'Công ty đạt lợi nhuận sau thuế tăng 98,6% so với cùng kỳ chủ yếu nhờ thu nhập từ nhượng bán tài sản, nhưng lợi nhuận từ hoạt động kinh doanh cốt lõi giảm. Nợ vay tăng, chi phí lãi vay cao, trong khi tiền mặt tăng do vay mới. Công ty cần cải thiện dòng tiền từ hoạt động kinh doanh và quản lý rủi ro nợ vay để đảm bảo phát triển bền vững.'),
('VTSS_2025_consolidated', 'VTSS', 2025, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là góp vốn của các cổ đông lớn, không phát sinh giao dịch mua bán hàng hóa/dịch vụ bất thường hoặc cho vay không lãi suất trong năm 2025. Rủi ro thấp.', 'Nợ phải trả toàn bộ là ngắn hạn (7,49 tỷ VND) và chiếm tỷ trọng rất nhỏ so với tổng tài sản ngắn hạn (2.987,8 tỷ VND). Công ty không có nợ dài hạn, áp lực trả nợ thấp, khả năng thanh toán tốt.', 'Công ty không có hàng tồn kho vật chất. Dự án xây dựng dở dang là phần mềm giao dịch chứng khoán, đang trong quá trình triển khai và không bị ứ đọng.', 2, 'Công ty vừa hoàn tất tăng vốn điều lệ từ 138 tỷ lên 3.036 tỷ VND trong năm 2025, tạo nền tảng mạnh mẽ để mở rộng hoạt động kinh doanh, đặc biệt là nghiệp vụ môi giới và cho vay ký quỹ. Doanh thu và lợi nhuận tăng trưởng đột biến. Cơ cấu tài chính an toàn với tỷ lệ nợ ngắn hạn rất thấp và thanh khoản tốt. Tuy nhiên, doanh thu và lợi nhuận phụ thuộc lớn vào lãi từ các khoản đầu tư và cho vay, cần theo dõi rủi ro thị trường và lãi suất.'),
('VTV_2016_consolidated', 'VTV', 2016, 'consolidated', 'Các giao dịch với bên liên quan bao gồm mua hàng từ công ty con và thanh toán phí tư vấn, lãi vay cho công ty mẹ. Tuy không có bằng chứng giao dịch bất thường rõ ràng, nhưng sự phụ thuộc vào công ty mẹ và công ty con có thể tiềm ẩn rủi ro về chuyển giá hoặc ưu đãi không công bằng.', 'Áp lực nợ vay cao với tổng nợ ngắn hạn 666 tỷ VNĐ và nợ dài hạn 50 tỷ VNĐ. Công ty có nhiều khoản vay ngân hàng lãi suất thả nổi, dễ chịu rủi ro lãi suất. Tài sản thế chấp chủ yếu cho dự án bất động sản, làm tăng rủi ro nếu dự án chậm tiến độ.', 'Hàng tồn kho chủ yếu là than cám, dễ bị ảnh hưởng bởi biến động giá nguyên liệu. Dự án tòa nhà Comatce đầu tư lớn, có nguy cơ chậm tiến độ hoặc tăng vốn, ảnh hưởng đến dòng tiền.', 6, 'Công ty có lợi nhuận tăng trưởng nhưng nợ vay cao, dòng tiền hoạt động kinh doanh âm do tăng tồn kho và phải thu. Phụ thuộc vào hệ sinh thái Vicem, rủi ro quản trị trung bình. Triển vọng phụ thuộc vào tiến độ dự án và quản lý vốn lưu động.'),
('VTSS_2024_consolidated', 'VTSS', 2024, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm thanh lý khoản đầu tư, mượn tiền và chi phí thuê văn phòng. Giá trị giao dịch không lớn so với tổng tài sản, nhưng có giao dịch cho mượn tiền và miễn tiền thuê văn phòng trong quá khứ, cho thấy rủi ro ở mức trung bình.', 'Nợ ngắn hạn chủ yếu là phải trả người bán với giá trị lớn, nhưng công ty có tiền và tương đương tiền cao, nên khả năng thanh toán tốt. Không có nợ dài hạn.', 'Chi phí xây dựng cơ bản dở dang là đầu tư vào hệ thống máy chủ và phần mềm, đây là dự án quan trọng cho hoạt động kinh doanh, không có dấu hiệu ứ đọng.', 6, 'Công ty đã chuyển từ lỗ sang lãi trong năm 2024 chủ yếu nhờ hoàn nhập dự phòng phải thu khó đòi. Doanh thu từ môi giới giảm, nhưng chi phí quản lý giảm mạnh. Công ty có kế hoạch tăng vốn thông qua chào bán cổ phiếu riêng lẻ. Triển vọng phụ thuộc vào thị trường chứng khoán và hiệu quả hoạt động kinh doanh.'),
('VTSS_2023_consolidated', 'VTSS', 2023, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm Phó chủ tịch HĐQT, các công ty liên quan. Các giao dịch chủ yếu là cho vay, mua bán tài sản và bảo lãnh. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Nợ vay rất thấp, chủ yếu là phải trả ngắn hạn không đáng kể (tổng nợ phải trả chỉ 207 triệu VNĐ). Không có áp lực nợ vay, khả năng thanh toán tốt.', 'Công ty là công ty chứng khoán, không có hàng tồn kho hay dự án xây dựng, nên không có rủi ro tồn kho dở dang hay ứ đọng.', 5, 'Công ty có tình hình tài chính ổn định với vốn chủ sở hữu lớn (hơn 91 tỷ VNĐ), nợ thấp. Tuy nhiên, hoạt động kinh doanh trong năm 2023 thua lỗ 311 triệu VNĐ, nhưng lỗ đã giảm đáng kể so với năm trước (3.7 tỷ VNĐ). Doanh thu chủ yếu từ môi giới chứng khoán giảm, chi phí quản lý giảm mạnh. Triển vọng phụ thuộc vào thị trường chứng khoán và khả năng cải thiện doanh thu.');
PRAGMA foreign_keys = ON;
